    _pPanel._isHorzTail = function () { return  (this._panel_slotbase & nexacro._PanelConst.SLOT_ARRANGETYPE_HORZTAIL); };
    _pPanel._isVertLead = function () { return !(this._panel_slotbase & nexacro._PanelConst.SLOT_ARRANGETYPE_VERTTAIL); };
    _pPanel._isVertTail = function () { return  (this._panel_slotbase & nexacro._PanelConst.SLOT_ARRANGETYPE_VERTTAIL); };
