    _pPanel._isFillSlot = function () { return  (this._panel_tempslot & nexacro._PanelConst.SLOT_VISIBLETYPE_FILLSLOT) > 0; };
    _pPanel._isTempSlot = function () { return  (this._panel_tempslot > 0); };
    _pPanel._isPartSlot = function () { return  (this._panel_partslot > 0); };

