    _pPanel._getPanelEachSizeWidth  = function (slotindex) { return slotindex >= 0 ? this._panel_eachsize[slotindex * 4 + 2] : undefined; };
    _pPanel._getPanelEachSizeHeight = function (slotindex) { return slotindex >= 0 ? this._panel_eachsize[slotindex * 4 + 3] : undefined; };

