                    hs = hc ? (sl ? (l < (bl - CW) ? 0 : (l - bl)) : (l > (bl + CW - w)) ? 0 : (bl + CW - (l + w))) : 0; // (this._getPanelMinLeft()) : (CW - this._getPanelMaxWidth())) : 0;

