    _pComplexComponent._onInitPopupSubPanelNCChildLayout = function (parent, startindex, startlevel, limitlevel, finalindex) { };  // 필요시 override
    _pComplexComponent._onInitPopupSubPanelChildLayout   = function (parent, startindex, startlevel, limitlevel, finalindex) { };  // 필요시 override
