    // [component.layout.panel:create]          // InitPanel에서 모두 전처리
    _pComplexComponent._createPanel = function ()
    {
        // unused
    };
    // [component.layout.panel:clear]           // 이부분 override는 basic component에서만
    _pComplexComponent._clearPanel = function ()
    {
        if (this._panel && !this._is_panel_ref)
        {
            this._panel._clear();
        }
    };
    // [component.layout.panel:reset]          // 이부분 override는 basic component에서만
    _pComplexComponent._resetPanelLayout = function (clearpanel, clearpopup)
    {
        if (clearpanel)
        {
            this._clearPanel();
        }

        if (clearpopup)
        {
            this._destroyPopupCrate();
            this._destroyPopupChild();
        }

        this._initPanelLayout();
    };


    // [component.layout.panel:get]                 // 이부분 override는 basic component에서만
    _pComplexComponent._getPanel = function ()
    {
        return this._panel;
    };
    // [component.layout.panel:get]                 // 이부분 override는 해당 component에서만
    _pComplexComponent._getSubPanel = function ()
    {
        return this._panel;
    };    
    _pComplexComponent._getPanelSlot = function (itemindex)
    {
        var panel = this._getPanel();
        if (panel)
        {
            return panel._getPanelSlot(itemindex);
        }

        return null;
    };
    _pComplexComponent._getPanelOverExpandSlot = function (expandindex)
    {
        var panel = this._getPanel();
        if (panel)
        {
            return panel._getPanelOverExpandSlot(expandindex, true);
        }

        return null;
    };
    _pComplexComponent._getPanelLimitHeight = function ()
    {
        if (nexacro._Browser == "IE" || (nexacro._Browser == "Edge" && nexacro._BrowserType == "Edge"))
        {
            return nexacro._PanelConst.PANEL_MAXHEIGHT_IE;
        }
        if (nexacro._Browser == "Gecko")
        {
            return nexacro._PanelConst.PANEL_MAXHEIGHT_GECKO;
        }

        return nexacro._PanelConst.PANEL_MAXHEIGHT_DEFAULT;
    };

    // [component.layout.panel.slot:clear]          // 이부분 override는 basic component에서만
    _pComplexComponent._clearPanelSlot = function ()
    {
        var panel = this._panel;

        if (panel)
        {
            // clear slot
            if (panel._isPartSlot())
                panel._clearPanelSlot(this._getBindCount() * this._body_count + this._head_count + this._tail_count);
            else
                panel._clearPanelSlot();
        }
    };

    // [component.layout.panel:direction]           // 이부분 override는 basic component에서만
    _pComplexComponent._isRowFirst = function () { return this._panel ? this._panel._isRowFirst() :  this._onCheckRowFirst(); };
    _pComplexComponent._isColFirst = function () { return this._panel ? this._panel._isColFirst() : !this._onCheckRowFirst(); };
    _pComplexComponent._isHorzLead = function () { return this._panel ? this._panel._isHorzLead() : true;  };
    _pComplexComponent._isHorzTail = function () { return this._panel ? this._panel._isHorzTail() : false; };
    _pComplexComponent._isVertLead = function () { return this._panel ? this._panel._isVertLead() : true;  };
    _pComplexComponent._isVertTail = function () { return this._panel ? this._panel._isVertTail() : false; };

    // [component.layout.panel:direction]           // 이부분 override
    _pComplexComponent._onCheckRowFirst = function () { return !this._is_colfirst; };

    // [component.layout.panel.slot:reset]          // 이부분 override는 basic component에서만
    _pComplexComponent._isPanelSlotReset = function ()
    {
        return this._panel ? this._panel._panel_resetslot == true : false;
    };
    // [component.layout.panel.slot:reset]          // 이부분 override는 basic component에서만
    _pComplexComponent._resetPanelSlot = function (ctrls, start, count, prevc, nextc, over)
    {
        // TODO : resetPanelSlotChild/resetPanelSlotItem으로 분리할것

        // trace("_resetPanelSlot:" + ",s=" + start + ",v=" + count + ",p=" + prevc + ",n=" + nextc + ",over=" + over);

        var panel = this._panel;

        if (panel)
        {
            panel._panel_resetslot = true;

            var slot;
            var headslot, tailslot;

            // check level/status
            var leveled = this._is_levelbind && this._databind != null;
            var formats = this._is_format_layout && this._formats != null;
            var childpan = this._is_child && ctrls == this._children;
            var partitem = this._is_items && ctrls == this._items && this._use_partitem;
          //var partslot = panel._panel_partslot;
          //var rowfirst = panel._isRowFirst();
            var indexed = panel._panel_layout == nexacro._PanelSlotConst.LAYOUTSTYLE_ROWCOL;
          //var posited = panel._panel_layout == nexacro._PanelSlotConst.LAYOUTSTYLE_POSITION;
          //var autosize = panel._panel_autosize;
          //var autofill = panel._panel_autofill;
            var startidx = panel._panel_idxstart ?? 0;
            var startlvl = panel._panel_lvlstart ?? 0;
            var limitlvl = panel._panel_lvllimit ?? Number.POSITIVE_INFINITY;
            var beginlvl = panel._panel_lvlbegin ?? 0;
            var subgroup = panel._panel_subgrpval;
            var substyle = panel._panel_substyles;
            var countlvl = panel._panel_sublevels; // Math.min(limitlvl - startlvl + 1, substyle.length); if (countlvl <= 0 || !Number.isFinite(countlvl)) countlvl = 1;
            var nonestat = nexacro._PanelSlotConst.STATUS_NONE;
            var bandstat = nexacro._PanelSlotConst.STATUS_NONE;
            var itemstat = nexacro._PanelSlotConst.STATUS_NONE;
            var slotstat = nexacro._getNewArray(countlvl, nexacro._PanelSlotConst.STATUS_NONE);
            var oncestat = nexacro._getNewArray(countlvl, nexacro._PanelSlotConst.STATUS_NONE);
            var slotshow = nexacro._getNewArray(countlvl, true);
            var collapse = false;
            var checkonce = false;
            var slotpopup = false;
          //var bandhide = false;
          //var bandpopup = false;

            // check size
            /*
            if (partitem || partslot)
            {
                if (this._getClientWidth() <= 0 || this._getClientHeight() <= 0)
                    return;
            }
            */

            if (nexacro._isArray(substyle))
            {
                // check substyle
                for (let l = 0; l < countlvl; l++)
                {
                    // check sub status
                    switch (substyle[l] & nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_MASK)
                    {
                        case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_EXPAND     : slotstat[l] = nexacro._PanelSlotConst.STATUS_EXPAND;      break;
                        case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_COLLAPSE   :
                        case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_ACCORDION  : slotstat[l] = nexacro._PanelSlotConst.STATUS_COLLPASE;    break;
                    //  case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_CLOSE      :     
                        case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_POPUP      : slotstat[l] = nexacro._PanelSlotConst.STATUS_CLOSE;       break;
                    }

                    // check first expand
                    if (substyle[l] & nexacro._PanelConst.GROUPING_SUBSTYLE_NONE_EXPAND_FIRST)
                    {
                        checkonce = true;
                        oncestat[l] = nexacro._PanelSlotConst.STATUS_EXPAND;
                    }
                    else
                    {
                        oncestat[l] = slotstat[l];
                    }
                }

                // check slotshow
                for (let l = 0; l < countlvl; l++)
                {
                    if (slotstat[l] == nexacro._PanelSlotConst.STATUS_COLLPASE)
                    {
                        for (let v = l+1; v < countlvl; v++) slotshow[v] = false; break;
                    }
                }
            }
            else
            {
                // check subgroup
                switch (subgroup & nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_MASK)
                {
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_EXPAND     : slotstat[0] = nexacro._PanelSlotConst.STATUS_EXPAND;                                          break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_COLLAPSE   :
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_ACCORDION  : slotstat[0] = nexacro._PanelSlotConst.STATUS_COLLPASE;    collapse = true;                    break;
                //  case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_CLOSE      :     
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_POPUP      : slotstat[0] = nexacro._PanelSlotConst.STATUS_CLOSE;       collapse = true; slotpopup = true;  break;
                }
            }
            {
                // check subband
                switch (subgroup & nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_MASK)
                {
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_EXPAND      : bandstat = nexacro._PanelSlotConst.STATUS_EXPAND;                                             break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_COLLAPSE    :
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_ACCORDION   : bandstat = nexacro._PanelSlotConst.STATUS_COLLPASE; /*bandhide = true;*/                      break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_POPUP       :
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_CLOSE       : bandstat = nexacro._PanelSlotConst.STATUS_CLOSE;    /*bandhide = true; bandpopup = true;*/    break;
                }
            }


            // check index,count
            var slotindex = 0;
            var itemindex = 0;
            var bindindex = 0;
            var ctrlindex = 0;
            var baseindex = 0;

            var ctrlcount = ctrls ? ctrls.length : 0;
            var bindcount = this._getBindCount();
            var nullcount = bindcount ? 0 : this._null_count;
            var slotcount = 0;
            var headcount;
            var tailcount;

            // check slot index/count
            if (childpan)
            {
                // check nobind children
                slotindex = 0;
                slotcount = ctrlcount;
            }
            else
            {
                // check null or bind
                bindcount = bindcount ? bindcount : nullcount;

                // check head or tail
                headslot = start < 0 || count < 0;
                tailslot = start < 0 || count < 0;

                // TODO : part + level의 경우 bindindex 등 index 재처리
                if (over)
                {
                    // check prev slot
                    if (over < 0)
                    {
                        if (over < -count)
                        {
                            slotindex = start - prevc; if (slotindex < 0) slotindex = 0;
                            slotcount = slotindex + count + prevc + nextc; if (slotcount >= bindcount) slotcount = bindcount;
                        }
                        else
                        {
                            slotindex = start - prevc + (over + 1); if (slotindex < 0) slotindex = 0;
                            slotcount = slotindex + count; if (slotcount >= bindcount) slotcount = bindcount;
                        }
                    }
                    // check next slot
                    if (over > 0)
                    {
                        if (over > count)
                        {
                            slotindex = start - prevc; if (slotindex < 0) slotindex = 0;
                            slotcount = slotindex + count + prevc + nextc; if (slotcount >= bindcount) slotcount = bindcount;
                        }
                        else
                        {
                            slotindex = start + count - (over - 1); if (slotindex >= bindcount) slotindex = bindcount;
                            slotcount = slotindex + count; if (slotcount >= bindcount) slotcount = bindcount;
                        }
                    }

                    // check index
                    bindindex = nullcount ? -4 : (slotindex - this._getItemHeadCount());
                    ctrlindex = 0;

                    if (slotindex >= 0)
                    {
                        ctrlindex = this._use_headitem > 0 ? this._getPanelSlotTargetCount(-1) : 0;
                        ctrlindex += bindindex > 0 ? bindindex * this._getPanelSlotTargetCount(0) : 0;
                    }
                }
                else
                {
                    // check head/tail
                    headcount = this._getItemHeadCount();
                    tailcount = this._getItemTailCount();

                    // check slot
                    slotindex = (!start || start < 0 || headslot) ? (baseindex - headcount) : Math.max(baseindex + start - prevc, 0);
                    slotcount = (!count || count < 0 || tailslot) ? (bindcount + tailcount) : Math.min(slotindex + count + prevc + nextc, bindcount);

                    // check index
                    if (slotpopup && leveled)
                    {
                        bindindex = nullcount ? -4 : startidx;
                        ctrlindex = !headslot && !tailslot ? headcount : 0;
                    }
                    else
                    {
                        bindindex = nullcount ? -4 : slotindex;
                        ctrlindex = !headslot && !tailslot ? headcount : 0;
                        ctrlindex += bindindex > 0 ? bindindex * this._getPanelSlotTargetCount(0) : 0;
                    }
                }
            }

            var curlvl, curidx, curfit, prelvl, ctrcnt, coords;
            var lvlgrp, lvlitr;
            var ctrl, ctr;
            var ctrlstart = ctrlindex, slotstart = slotindex, bindstart = bindindex;

            if (slotpopup || leveled) // if (slotpopup && leveled && collapse)
            {
                panel._initPanelBindList(bindcount);

                if (partitem)
                {
                    // leveled popup/collapse + partitem : make ctrl slot same level from ctrllist
                    for (itemindex = bindindex; ctrlindex < ctrlcount && slotindex < slotcount; itemindex++, bindindex++)
                    {
                        // 확인 : ctrlindex/bindindex/itemindex/slotindex간 변환확인
                        ctrl = this._getItem(itemindex); if (!ctrl) continue;
                        ctr = nexacro._isArray(ctrl) ? ctrl[0] : ctrl; if (!ctr) continue;

                        curlvl = this._getItemLevel(ctr) ?? startlvl;
                        curidx = this._getItemIndex(ctr) ?? ctrlindex;
                        curfit = this._getItemFitSize(ctr);

                        if (formats)
                        {
                            coords = this._getItemCoords(ctr) ?? (indexed ? this._fetchFormatsRowCols(curidx) : this._fetchFormatsPosition(curidx));
                            ctrcnt = coords.length;
                        }
                        else
                        {
                            ctrcnt = this._getPanelSlotTargetCount(itemindex);
                        }

                        if ((curlvl >= startlvl && curlvl <= limitlvl) || (bindindex < startidx))
                        {
                            slot = panel._getPanelSlot(itemindex, true);
                            if (slot)
                            {
                                lvlgrp = this._getItemLevelSubGroup(ctrl) ?? 0;
                                lvlitr = curlvl - startlvl; 
                                
                                if (lvlitr <  0)        lvlitr = 0;
                                if (lvlitr >= countlvl) lvlitr = countlvl - 1;

                                slot._setBindIndex(bindindex);
                                slot._setSlotTarget(ctrl, slotindex);
                                slot._setSlotLevel(curlvl);
                                slot._setSlotStatusSet(lvlgrp ? slotstat[lvlitr] : nonestat, bandstat);
                                slot._setSlotVisible(slotshow[lvlitr]);

                                if (indexed)
                                    slot._setSlotRowCols(coords, curfit);
                                else
                                    slot._setSlotPosition(coords, curfit);

                                panel._setPanelBindbyBindIndex(bindindex, [curlvl, itemindex]);
                            }

                            ctrlindex += ctrcnt;
                            slotindex++;
                        }
                        else if (curlvl < beginlvl)
                        {
                            break;
                        }
                    }
                }
                else
                {
                    // leveled popup/collapse + no partitem: make ctrl slot same level from ctrllist
                    for (; ctrlindex < ctrlcount && slotindex < slotcount; slotindex++, ctrlindex += ctrcnt)
                    {
                        ctrl = ctrls[ctrlindex]; if (!ctrl) continue;

                        curlvl = this._getItemLevel(ctrl) ?? startlvl;
                        curidx = this._getItemBindIndex(ctrl) ?? ctrlindex;
                        curfit = this._getItemFitSize(ctrl);

                        if (formats)
                        {
                            coords = this._getItemCoords(ctrl) ?? (indexed ? this._fetchFormatsRowCols(curidx) : this._fetchFormatsPosition(curidx));
                            ctrcnt = coords.length;
                        }
                        else
                        {
                            ctrcnt = this._getPanelSlotTargetCount(curidx);
                        }

                        if ((curlvl >= startlvl && curlvl <= limitlvl) || (curidx < startidx))
                        {
                            slot = panel._getPanelSlot(slotindex, true);
                            if (slot)
                            {
                                lvlgrp = this._getItemLevelSubGroup(ctrl) ?? 0;
                                lvlitr = curlvl - startlvl; 
                                
                                if (lvlitr <  0)        lvlitr = 0;
                                if (lvlitr >= countlvl) lvlitr = countlvl - 1;

                                slot._setBindIndex(curidx);
                                slot._setSlotTarget(ctrcnt > 1 ? nexacro._getSubArray(ctrls, ctrlindex, ctrcnt) : ctrl, slotindex);
                                slot._setSlotLevel(curlvl);
                                slot._setSlotStatusSet(lvlgrp ? slotstat[lvlitr] : nonestat, bandstat);
                                slot._setSlotVisible(slotshow[lvlitr]);

                                if (indexed)
                                    slot._setSlotRowCols(coords, curfit);
                                else
                                    slot._setSlotPosition(coords, curfit);

                                panel._setPanelBindbyBindIndex(curidx, [curlvl, slotindex]);
                            }
                        }
                    }
                }

                panel._trimPanelBindList();
            }
            else
            {
                panel._initPanelBindList(-1);

                // no leveled popup/expand : make ctrl slot from full slotlist & binditem
                for (itemindex = bindindex; ctrlindex < ctrlcount && slotindex < slotcount; slotindex++, itemindex++, bindindex++)
                {
                    slot = panel._getPanelSlot(itemindex, true);
                    if (slot)
                    {
                        slot._setBindIndex(bindindex);
                        slot._setSlotStatusSet(slotstat[0], bandstat);

                        // TODO : ListView 확인하여 1번만 fetch 또는 cache로 변경
                        if (indexed)
                            coords = this._fetchFormatsRowCols(bindindex);
                        else
                            coords = this._fetchFormatsPosition(bindindex);

                        ctrcnt = coords.length;

                        if (ctrcnt > 1)
                        {
                            var ctrls = partitem ? this._getItem(itemindex) : nexacro._getSubArray(ctrls, ctrlindex, ctrcnt);
                            var ctrl = ctrls[0];

                            slot._setSlotTarget(ctrls, slotindex);
                            ctrlindex += ctrcnt;

                            curfit = this._getItemFitSize(ctrl);
                        }
                        else
                        {
                            var ctrl = partitem ? this._getItem(itemindex) : ctrls[ctrlindex];

                            slot._setSlotTarget(ctrl, slotindex);
                            ctrlindex++;

                            curfit = this._getItemFitSize(ctrl);
                        }

                        if (indexed)
                            slot._setSlotRowCols(coords, curfit);
                        else
                            slot._setSlotPosition(coords, curfit);

                        if (leveled)
                        {
                            curlvl = this._bringLevelBindValue(bindindex);

                            slot._setSlotLevel(curlvl);
                            slot._setSlotVisible(!collapse || curlvl <= startlvl);
                        }

                        //  panel._setPanelSlot(slotindex, slot);
                    }
                    else
                    {
                        ctrlindex++;
                    }
                }
            }

            // make empty slot
            if (panel._isTempSlot())
            {
                for (let l = slotindex + (panel._isFillSot() ? slotcount : 1); slotindex < l; slotindex++)
                {
                    slot = panel._getPanelSlot(slotindex, true);
                    if (slot)
                    {
                        if (indexed)
                            slot._setSlotRowCols();
                        else // if (posited)
                            slot._setSlotPosition();

                        //  panel._setPanelSlot(slotindex, slot);
                    }
                }
            }

            // TODO : 전체생성이라면 미리생성
            // reset slot count
            if (!partitem && slotindex < slotcount)
            {
                panel._setPanelSlotLength(ctrlcount);
            }

            // checkonce
            if (checkonce && (slotpopup || leveled))
            {
                // expand 1'st/n'st once
                for (let i = 0, l = oncestat.length, slotidx = slotstart, k = true, g = false; k && i < l; i++)
                {
                    for (; slotidx < slotcount; slotidx++)
                    {
                        var slot = panel._getPanelSlot(slotidx);
                        if (slot)
                        {
                            prelvl = curlvl;
                            curlvl = slot._getSlotLevel();
                            lvlitr = curlvl - startlvl;

                            if (g && lvlitr <= 0)
                            {
                                k = false;
                                break;
                            }

                            if (slot._getSlotStatus() < 0)
                            {
                                panel._setPanelSlotStatus(slotidx, oncestat[lvlitr]);
                                g = true;
                                break;
                            }
                        }
                    }
                }
            }

            // make slot static 
            // TODO : command create
            /*
            if (panel._isShowSlot())
            {
                for (i = 0, l = slotcount; i < l; i++)
                {
                    slot = panel._getPanelSlot(slotindex, false);
                    if (slot)
                    {
                        slot._setSlotStatic(new nexacro._IconText("slot"));
                    }
                }
            }
            */
        }
    };

    // [component.layout.panel.slot.part:show]         // 필요시 override
    _pComplexComponent._showPanelItemSlot = function (ctrls, start, count, prevc, nextc, over, show, band)
    {
        // TODO : _resetPanelSlot 소스 공유
        // TODO : Head/Tail Show/Hide 처리

        // trace((show === false ? ("hideslot:") : (band === 0 ? "makeslot:" : "showslot:")) + start + "," + count + "," + prevc+ "," + nextc + ",over=" + over);

        var panel = this._panel;
        if (panel && this._use_partitem && ctrls)
        {
            // check level/status
            var leveled = this._is_levelbind && this._databind != null;
            var formats = this._is_format_layout && this._formats != null;
            var startidx = panel._panel_idxstart !== undefined ? panel._panel_idxstart : 0;
            var startlvl = panel._panel_lvlstart !== undefined ? panel._panel_lvlstart : 0;
            var limitlvl = panel._panel_lvllimit !== undefined ? panel._panel_lvllimit : Number.POSITIVE_INFINITY;
         // var slotstat = nexacro._PanelSlotConst.STATUS_NONE;
         // var bandstat = nexacro._PanelSlotConst.STATUS_NONE;
            var collapse = false;
         // var bandhide = false;
            var slotpopup = false;
         // var bandpopup = false;
            var slotstat;
            var bandstat;
            var bandhide;
            var bandpopup;

            // 확인 : 아래 수정된 코드 재확인 할것 (현재 ListView 는 BAND Status, MegaMenu는 GroupStatus 사용중)

            // check subgroup
            var subgroup = panel._panel_subgrpval & nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_MASK;
            if (subgroup)
            {
                switch (subgroup)
                {
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_EXPAND     : slotstat = nexacro._PanelSlotConst.STATUS_EXPAND;                                         break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_COLLAPSE   :
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_ACCORDION  : slotstat = nexacro._PanelSlotConst.STATUS_COLLPASE; collapse = true;                      break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_GROUP_POPUP      : slotstat = nexacro._PanelSlotConst.STATUS_COLLPASE; collapse = true; slotpopup = true;    break;
                }
            }
            // check subband
            var subband = panel._panel_subgrpval & nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_MASK;
            if (subband)
            {
                switch (subband)
                {
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_EXPAND      : bandstat = nexacro._PanelSlotConst.STATUS_EXPAND;                                         break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_COLLAPSE    : bandstat = nexacro._PanelSlotConst.STATUS_COLLPASE; bandhide = true;                      break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_ACCORDION   : bandstat = nexacro._PanelSlotConst.STATUS_COLLPASE; bandhide = true;                      break;
                    case nexacro._PanelConst.GROUPING_SUBSTYLE_BAND_POPUP       : bandstat = nexacro._PanelSlotConst.STATUS_COLLPASE; bandhide = true; bandpopup = true;    break;
                }
            }

            // check index,count
            var slotindex = 0;
            var itemindex = 0;
            var bindindex = 0;
            var ctrlindex = 0;
            var baseindex = 0;

            var ctrlcount = ctrls.length;
            var bindcount = this._getBindCount();
            var slotcount = 0;

            var headcount = this._getItemHeadCount();
         // var tailcount = this._getItemTailCount();

            // check slot
            slotindex = (!start || start < 0) ? baseindex : Math.max(baseindex + start - prevc, 0);
            slotcount = (!count || count < 0) ? bindcount : Math.min(slotindex + count + prevc + nextc, bindcount);

            // check index
            bindindex = itemindex = slotindex;
            ctrlindex = headcount * this._getPanelSlotTargetCount(-1) + bindindex * this._getPanelSlotTargetCount(0);

            // check over : TODO innerover/outerover optimize
            /*
            if (over)
            {
                // check prev slot
                if (over < 0)
                {
                    if (over > -count)
                    {
                        // prev over inner
                    }
                    else
                    {
                        // prev over outer
                    }
                }
                // check next slot
                if (over > 0)
                {
                    if (over < count)
                    {
                        // next over inner
                    }
                    else
                    {
                        // next over outer
                    }
                }
            }
            */

            if (!panel._panel_showslot)
            {
                var curlvl;
                var slot;

                if (formats)
                {
                    if (slotpopup || leveled) // if (slotpopup && leveled && collapse)
                    {
                        // formats + leveled popup/collapse : make ctrl slot same level
                        for (; ctrlindex < ctrlcount && slotindex < slotcount; slotindex++, itemindex++, bindindex++)
                        {
                            curlvl = this._fetchLevelBindValue(bindindex);
                            if ((curlvl >= startlvl && curlvl <= limitlvl) || (bindindex < startidx))
                            {
                                // 확인 : ctrlindex/bindindex/itemindex/slotindex간 변환확인
                                slot = panel._getPanelSlot(itemindex, true);
                                if (slot)
                                {
                                    if (show === false)
                                    {
                                        // Detach & Destroy PartItem
                                        slot._clearSlotTarget(this._delItem(itemindex, true));
                                    }
                                    else
                                    {
                                        // Create & SetSize PartItem
                                        slot._placeSlotTarget(this._getItem(itemindex, true));
                                    }

                                    ctrlindex += this._getPanelSlotTargetCount(itemindex);
                                }
                                else
                                {
                                    ctrlindex++;
                                }
                            }
                            else if (curlvl > startlvl)
                            {
                                continue;
                            }
                            else // if (curlvl < startlvl)
                            {
                                break;
                            }
                        }
                    }
                    else
                    {
                        // trace((show === false ? ("hideslot:") : (band === 0 ? "makeslot:" : "showslot:")) + slotindex + "->" + (slotcount - 1));

                        // formats + no leveled popup/collaps : make ctrl slot
                        for (; ctrlindex < ctrlcount && slotindex < slotcount; slotindex++, itemindex++)
                        {
                            // 확인 : itemindex 확인
                            slot = panel._getPanelSlot(itemindex, true);
                            if (slot)
                            {
                                if (show === false)
                                {
                                    // Detach & Destroy PartItem
                                    slot._clearSlotTarget(this._delItem(itemindex, true));
                                }
                                else
                                {
                                    // Create & SetSize PartItem
                                    slot._placeSlotTarget(this._getItem(itemindex, true));
                                }

                                ctrlindex += this._getPanelSlotTargetCount(itemindex);
                            }
                            else
                            {
                                ctrlindex++;
                            }
                        }
                    }

                    // for empty slot
                    /*
                        for (; slotindex < slotcount; slotindex++)
                        {
                            var slot = panel.__getPanelSlot(slotindex, true);
 
                            if (slot)
                            {
                            }
                        }
                    */
                }
                else
                {
                    if (slotpopup || leveled) // if (slotpopup && leveled && collapse)
                    {
                        // no formats + leveled popup/collapse : make ctrl slot same level
                        for (; ctrlindex < ctrlcount && slotindex < slotcount; slotindex++, itemindex++, bindindex++)
                        {
                            curlvl = this._fetchLevelBindValue(bindindex);
                            if ((curlvl >= startlvl && curlvl <= limitlvl) || (bindindex < startidx))
                            {
                                // 확인 : itemindex 확인
                                slot = panel._getPanelSlot(itemindex, true);
                                if (slot)
                                {
                                    if (show === false)
                                    {
                                        // Detach & Destroy PartItem
                                        slot._clearSlotTarget(this._delItem(itemindex, true));
                                    }
                                    else
                                    {
                                        // Create & SetSize PartItem
                                        slot._placeSlotTarget(this._getItem(itemindex, true));
                                    }

                                    ctrlindex += this._getPanelSlotTargetCount(itemindex);
                                }
                                else
                                {
                                    ctrlindex++;
                                }
                            }
                            else if (curlvl > startlvl)
                            {
                                continue;
                            }
                            else // if (curlvl < startlvl)
                            {
                                break;
                            }
                        }
                    }
                    else
                    {
                        // no foramts + no leveled popup/collapse : make ctrl slot
                        for (; ctrlindex < ctrlcount && slotindex < slotcount; slotindex++, itemindex++)
                        {
                            // 확인 : itemindex 확인
                            slot = panel._getPanelSlot(itemindex, true);
                            if (slot)
                            {
                                if (show === false)
                                {
                                    // Detach & Destroy PartItem
                                    slot._clearSlotTarget(this._delItem(itemindex, true));
                                }
                                else 
                                {
                                    // Create & SetSize PartItem
                                    slot._placeSlotTarget(this._getItem(itemindex, true));
                                }

                                ctrlindex += this._getPanelSlotTargetCount(itemindex);
                            }
                        }
                    }

                    // for empty slot
                    /*
                        for (; slotindex < slotcount; slotindex++)
                        {
                            var slot = panel.__getPanelSlot(slotindex, true);
 
                            if (slot)
                            {
                            }
                        }
                    */
                }
            }
            else
            {
                // TODO: Slot View
                /*
                    var view = new nexacro._IconText("view");
                    var slot = new nexacro._PanelSlot(ctrl, view);
 
                    if (slot)
                    {
                        panel._addPanelSlot(slot);
                    }
                */
            }
        }
    };
    // [component.layout.panel.slot.part:hide]         // 필요시 override
    _pComplexComponent._hidePanelItemSlot = function (ctrls, start, count, prevc, nextc, over)
    {
        // trace("hideslot|" + start + "," + count + "," + prevc + "," + nextc);

        if (this._use_partitem)
        {
            // hide range
            var prevs = 0;
            var preve = start - prevc;
            var nexts = start + count + nextc;
            var nexte = this._getBindCount();

            // hide prev
            if (preve && prevs < preve)
                this._showPanelItemSlot(ctrls, prevs, preve, 0, 0, 0, false, 0);

            // hide next
            if (nexte && nexts < nexte)
                this._showPanelItemSlot(ctrls, nexts, nexte, 0, 0, 0, false, 0);
        }
    };
    // [component.layout.panel.slot.part:make]         // 필요시 override
    _pComplexComponent._makePanelItemSlot = function (ctrls, start, count, prevc, nextc, band, rowfirst)
    {
        // trace("makeslot|" + start + "," + count + "," + prevc + "," + nextc);

        if (this._use_partitem && ctrls && ctrls.length)
        {
            var headcnt = this._head_count ? this._head_count : 0;
            var tailcnt = this._tail_count ? this._tail_count : 0;
            var bindcnt = this._getBindCount();

            if (!band)
            {
                var mkcnt = count * this._add_partitem * this._acc_partitem;
                var views = start;
                var viewf = start + count;
                var dscnt = bindcnt;

                // make prev
                if (views - prevc > headcnt)
                {
                    var _prevs = views - mkcnt;
                    var _prevc = mkcnt - prevc;

                    if (_prevs < headcnt)
                    {
                        _prevc += _prevs;
                        _prevs = 0;
                    }

                    if (_prevc > headcnt)
                    {
                        this._showPanelItemSlot(ctrls, _prevs, _prevc, 0, 0, 0, true, 0);

                        this._setItemScrollPrevCount(_prevc + prevc);
                        this._resetItemScrollFullSize(rowfirst);
                    }
                }

                // make next
                if (viewf + nextc < dscnt)
                {
                    var _nexts = viewf + nextc;
                    var _nexto = dscnt - (viewf + mkcnt);
                    var _nextc = mkcnt - nextc;

                    if (_nexto < tailcnt)
                    {
                        _nextc += _nexto;
                    }

                    if (_nextc > tailcnt)
                    {
                        this._showPanelItemSlot(ctrls, _nexts, _nextc, 0, 0, 0, true, 0);

                        this._setItemScrollNextCount(_nextc + nextc);
                        this._resetItemScrollFullSize(rowfirst);
                    }
                }

                return true;
            }
            if (band == -1)
            {
                // make head
                var heads = 0;
                var headc = headcnt;
                if (headc > 0)
                {
                    this._showPanelItemSlot(ctrls, heads, headc, 0, 0, 0, true, -1);
                }

                return true;
            }
            if (band == -2)
            {
                // make tail
                var tails = headcnt + bindcnt;
                var tailc = tailcnt;
                if (tailc > 0)
                {
                    this._showPanelItemSlot(ctrls, tails, tailc, 0, 0, 0, true, -2);
                }

                return true;
            }
        }
    };
