    _pComplexComponent._initPanelLevelStartInfo = function (idx, lvl, lmt, fin)
    {
        // TODO : 상하위 2개+1개 변수쌍 --> 1개로 통합 (상위-->하위, 하위-->상위 항상 서로 값이 같도록 Sync 해야함)
        this._setPanelStartLevel(lvl); this.__panel_lvlstart = lvl;
        this._setPanelLimitLevel(lmt); this.__panel_lvllimit = lmt;
        this._setPanelStartIndex(idx); this.__panel_idxstart = idx;
        this._setPanelFinalIndex(fin); this.__panel_idxfinal = fin;
    };

    // [component.layout.panel:getinfo]
    _pComplexComponent._getPanelStartIndex = function ()
    {
        // return popup info
        if (this.__panel_idxstart !== undefined) return this.__panel_idxstart;
        // return normal info
        return this._panel ? this._panel._panel_idxstart : 0;
    };
    _pComplexComponent._getPanelFinalIndex = function ()
    {
        // return popup info
        if (this.__panel_idxfinal !== undefined) return this.__panel_idxfinal;
        // return normal info
        return this._panel ? this._panel._panel_idxfinal : undefined;
    };
    _pComplexComponent._getPanelStartLevel = function ()
    {
        // return popup info
        if (this.__panel_lvlstart !== undefined) return this.__panel_lvlstart;
        // return normal info
        return this._panel ? this._panel._panel_lvlstart : 0;
    };
    _pComplexComponent._getPanelLimitLevel = function ()
    {
        // return popup info
        if (this.__panel_lvllimit !== undefined) return this.__panel_lvllimit;
        // return normal info
        return this._panel ? this._panel._panel_lvllimit : Number.POSITIVE_INFINITY;
    };
    _pComplexComponent._getPanelBeginLevel = function ()
    {
        // return popup info
        if (this.__panel_lvlbegin !== undefined) return this.__panel_lvlbegin;
        // return normal info
        return this._panel ? this._panel._panel_lvlbegin : 0;
    };    
    _pComplexComponent._getPanelLevelIndent = function ()
    {
        // return indent size
        return 0;
    };
    _pComplexComponent._getPanelSlotTargetCount = function (itemindex, checkslot)
    {
        // return slot target count
        return this._panel ? this._panel._getSlotTargetCount(itemindex, checkslot) : 0;
    };

    // 확인 : use level 일때 no level bind의 경우 root level 처리
    _pComplexComponent._isBindRootLevel = function (l) { return (this._start_level) == (l ?? 0); }
    _pComplexComponent._isBindLeafLevel = function (l) { return (this._final_level) == (l ?? 0); }

    _pComplexComponent._setBindRootLevel = function (root)
    {
        this._start_level = root;
    };
    _pComplexComponent._setBindLeafLevel = function (leaf)
    {
        this._final_level = leaf;
    };    
    _pComplexComponent._getBindRootLevel = function ()
    {
        // return component bind data root level  (levelcolumn start value)
        // 0 >= : use bind level (default:0)
        // -1   : not bind level (not use level) 
        return this._start_level ?? (this._is_levelbind ? 0 : 0);  // -1
    };
    _pComplexComponent._getBindLeafLevel = function ()
    {
        // return component bind data root level  (levelcolumn final value)
        // 0 >= : use bind level (default:0)
        // -1   : not bind level (not use level) 
        return this._final_level ?? (this._is_levelbind ? 2 : 2);  // -1
    };
    // 확인 : use level 일때 no level format의 경우 root level 처리
    _pComplexComponent._getBandRootLevel = function ()
    {
        // return component format band root level (format band root index)
        // 0 >= : use leveled band format (default:0)
        // -1   : not leveled band format (not use level) 
        return this._is_format_chklvl ? nexacro._FormatsConst.FORMATBANDIDX_ROOT : -1;
    };
    _pComplexComponent._getBandBrchLevel = function ()
    {
        // return component format band root level (format band root index)
        // 0 >= : use leveled band format (default:0)
        // -1   : not leveled band format (not use level) 
        return this._is_format_chklvl ? this._final_level !== undefined ? nexacro._FormatsConst.FORMATBANDIDX_BRCH : nexacro._FormatsConst.FORMATBANDIDX_SUB : -1;
    };
    _pComplexComponent._getBandLeafLevel = function ()
    {
        // return component format band root level (format band root index)
        // 0 >= : use leveled band format (default:0)
        // -1   : not leveled band format (not use level) 
        return this._is_format_chklvl ? this._final_level !== undefined ? nexacro._FormatsConst.FORMATBANDIDX_LEAF : nexacro._FormatsConst.FORMATBANDIDX_FIN : -1;
    };

    // [component.layout.panel:getskipinfo]         // override 없음
    _pComplexComponent._getPanelSkipLevel = function (slot, itemidx)
    {
        return this._onGetPanelSkipLevel(slot, itemidx);
    }
    /*
    _pComplexComponent._getPanelSkipIndex = function (slot, itemidx)
    {
        return this._onGetPanelSkipIndex(slot, itemidx);
    }
    */

    // [component.layout.panel:getskipinfo]         // 필요시 override
    _pComplexComponent._onGetPanelSkipLevel = function (slot, itemidx)
    {
        let currlvl, nextlvl;
        if (slot)
        {
            if (slot._isOverflowSlot()) return 0;

            if (this._is_format_chklvl && itemidx >= 0)
            {
                currlvl = slot._getSlotLevel();
                nextlvl = this._bringLevelBindValue(slot._getBindIndex() + 1);

                if (nextlvl !== undefined && currlvl !== undefined)
                    return nextlvl - currlvl;
            }
        }
    }
    /*
    _pComplexComponent._onGetPanelSkipIndex = function (slot, itemidx)
    {
    }
    */
    // [component.layout.panel:getdefslotstat]         // override 없음
    _pComplexComponent._getPanelDefSlotStat = function (l)
    {
        return this._panel ? this._panel._getDefSlotStat(l) : nexacro._PanelSlotConst.STATUS_NONE;
    }
    //===============================================================
    // nexacro.ComplexComponent : Layout/Popup
    //===============================================================

    // [Complex Component 처리]
    // Container Element를 Panel의 구현요소로 이용해 Layout 배치를 처리한다.
    // Panel 동작은 Rule Base Interface로 Socketing 구조로 확장한다.


    // [component.layout.panel.popup:create]        // Override 처리
    _pComplexComponent._createPanelPopup = function (slot, itemidx, isbandpopup, issameindex, issamelevel, skiplevel/*, skipindex*/)
    {
        if (!slot) return;

        // check band popup/item,ctrl popup/overflow popup
        isbandpopup = isbandpopup ?? this._isPanelSubBandPopup(slot._getSlotLevel());  // true : bandpopup, false : item,ctrl popup, -9 : overflowpopup
        issameindex = issameindex ?? isbandpopup;
        issamelevel = issamelevel ?? isbandpopup;
        skiplevel   = skiplevel   ?? this._getPanelSkipLevel(slot, itemidx);
    //  skipindex   = skipindex   ?? this._getPanelSkipIndex(slot, itemidx);

        // create popup crate control
        var popup = this._createPopupCrate(slot, itemidx, isbandpopup, issameindex, issamelevel, skiplevel/*, skipindex*/);

        // create popup child control
        var child = this._createPopupChild(slot, itemidx, isbandpopup, issameindex, issamelevel, skiplevel/*, skipindex*/);

        // created popup control
        if (popup)
        {
            // detach pre-create child
            var attcm = popup._getAttachedComponent();
            if (attcm)
            {
                popup._detach(attcm);
                attcm.destroy();
            }

            // attach child to popup
            if (child)
            {
                popup._attach(child);
            }

            popup.on_created();
        }

        // created subgroup child
        if (child)
        {
            child.on_created();
        }

        return popup;
    };

    // [component.layout.panel.popup:create]    // Override 제외
    _pComplexComponent._createPopupCrate = function (slot, itemindex, isbandpopup, issameindex, issamelevel, skiplevel /*, skipindex*/)
    {
        // create popup control
        var popup = slot._hasSlotPopup() ? slot._getSlotPopup() : this._onCreatePopupCrate();

        // set slot
        if (popup && slot)
        {
            // get popup info
            var popupindex = this._popuplist ? this._popuplist.length - 1 : -1;
            var pbindindex = slot._getBindIndex();
            var pslotlevel = slot._getSlotLevel();
            var startindex = pbindindex + (issameindex ? 0 : (/*skipindex ??*/ 1));   // 0:bandpopup or subtitle, 1:treepopup or nosubtitle    n:skip index (+n)
            var startlevel = pslotlevel + (issamelevel ? 0 : (  skiplevel ??   1));   // 0:bandpopup,             1:treepopup or subpopup,     n:skip level (+n)
            var limitlevel = this._getPanelLimitLevel()    + (  skiplevel ??   1);    // start=limit : popupmenu, start!=limit : groupmenu     limit<0 : unlimit fullgroup
            var finalindex = slot._isOverflowSlot() ? this._getBindCount() - this._getItemScrollFixTailCount() : undefined;

            // init popup info
            popup._initInfo(this, slot._getSlotTarget(), this._getRootComponent(this), popupindex, startindex, finalindex, startlevel, limitlevel, pbindindex, itemindex, isbandpopup, slot._isOverflowSlot(), issameindex, issamelevel);

            // set slot popup info
            slot._setSlotPopup(popup);

            // cache popup
            this._setCurrentPopup(popup);
        }

        return popup;
    };
    // [component.layout.panel.popup:destroy]   // Override 제외
    _pComplexComponent._destroyPopupCrate = function ()
    {
        if (this._popuplist)
        {
            // user unlink popupcontrol
            this._onDestroyPopupCrate();

            // clear subgroup
            this._clearPopupCrate();
        }
    };
    // [component.layout.panel.popup:clear]     // Override 제외
    _pComplexComponent._clearPopupCrate = function ()
    {
        if (this._popuplist)
        {
            // user unlink item : _onDestroyPopupControl 사용
            // this._onClearPopupCrate();

            // cache clear
            this._setCurrentPopup(null);

            var plist = this._popuplist;
            var count = plist.length;

            for (var i = count - 1; i >= 0; i--)
            {
                var popup = plist[i];
                if (popup)
                {
                    if (popup._isPopup && popup._closePopup) { if (popup._isPopup()) popup._closePopup(); }
                    if (popup._clear)  popup._clear();
                    if (popup.destroy) popup.destroy();

                    delete plist[i];
                }
            }

            this._popuplist.length = 0;
            this._popuplist = null;
        }
    };

    // [component.layout.panel.popup:create]        // Override 처리
    _pComplexComponent._createPopupControl = function (popup)
    {
        if (popup)
        {
            // set control
            /*
                popup._setControl(popup._type_name);
            */

            // create component
            if (popup.createComponent(true))
            {
                // check list
                if (!this._popuplist)
                    this._popuplist = [];

                // add list
                this._popuplist.push(popup);

                // return popup
                return popup;
            }
        }

        // return null
        return null;
    };
    // [component.layout.panel.popup:create]        // Override 처리
    _pComplexComponent._onCreatePopupCrate = function ()
    {
        var popup = null;

        if (popup = this._createPopupControl(new nexacro._PanelPopupControl("panelpopup", 0, 0, 0, 0, null, null, null, null, null, null, this)))
        {
            popup._type_name = "popup" + this._type_name;

            return popup;
        }
    };
    // [component.layout.panel.popup:destroy]       // Override 처리
    _pComplexComponent._onDestroyPopupCrate = function ()
    {
        // user prop unlink
    };

    // [component.layout.panel.subgroup:create]        // Override 제외
    _pComplexComponent._createPopupChild = function (slot, itemidx, isbandpopup, issameindex, issamelevel, skiplevel/*, skipindex*/)
    {
        if (slot)
        {
            // clear pre create child
        }

        // create subgroup complex component
        var child = this._onCreatePopupChild(slot, itemidx, isbandpopup, issameindex, issamelevel, skiplevel/*, skipindex*/);

        if (child)
        {
            // after create logic
        }

        return child;
    };
    // [component.layout.panel.subgroup:destroy]        // Override 제외
    _pComplexComponent._destroyPopupChild = function ()
    {
        if (this._popupchildlist)
        {
            // user unlink popup child
            this._onDestroyPopupChild();

            // clear popup child
            this._clearPopupChild();
        }
    };
    // [component.layout.panel.subgroup:clear]          // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._clearPopupChild = function ()
    {
        if (this._popupchildlist)
        {
            // user unlink item : _onDestroyPopupChild 사용
            // this._onClearPopupChild();

            // clear popup child list
            var clist = this._popupchildlist;
            var count = clist.length;

            for (var i = count - 1; i >= 0; i--)
            {
                var child = clist[i];
                if (child)
                {
                //  if (child._isPopup()) child._closePopup();
                    child.destroy();
                    delete clist[i];
                //  clist[i] = null;
                }
            }

            this._popupchildlist.length = 0;
            this._popupchildlist = null;
        }
    };

    // [component.layout.panel.subgroup:close]        // Override 제외
    _pComplexComponent._closePopup = function ()
    {
        if (this._popuplist)
        {
            var plist = this._popuplist;
            var count = plist.length;

            for (var i = count - 1; i >= 0; i--)
            {
                var popup = plist[i];
                if (popup && popup._isPopup()) popup._closePopup();
            }
        }

        nexacro.SimpleComponent.prototype._closePopup.call(this);
    };
    // [component.layout.panel.subgroup:close]        // 필요시 Override 처리
    _pComplexComponent._onClosePopup = function ()
    {
        // comp->popup_children->close : comp child close
        // this._resetStatus();
    };
    // [component.layout.panel.subgroup:close]        // 필요시 Override 처리
    _pComplexComponent._onClosePopupSelf = function ()
    {
        // comp->popup_container->close : comp self close
        this.clearSelect();
    };

    // [component.layout.panel.subgroup:close]        // Override 제외
    _pComplexComponent._closePopupSelf = function ()
    {
        nexacro.SimpleComponent.prototype._closePopupSelf.call(this);
    };
    // [component.layout.panel.subgroup:close]        // Override 제외
    _pComplexComponent._closePopupLeaf = function ()
    {
        var curr = this._getCurrentPopup();
        if (curr && curr._closePopup)
        {
            return curr._closePopup();
        }

        if (this._is_subcontrol)
        {
            if (this._p_parent)
            {
                return this._p_parent._closePopupLeaf();
            }
        }
        else
        {
            return this._closePopupSelf();
        }
    };

    // [component.layout.panel.subgroup:create]        // Override 제외
    _pComplexComponent._createPopupChildControl = function (child, slot, slotidx, issameindex, issamelevel, skiplevel/*, skipindex*/)
    {
        if (child)
        {
            // set control
            child._setControl(child._type_name);
            // set popup child
            child._setPopupContains(true);

            // create component         // TODO: InitSub 공통처리후 createComponent로 변경
            if (child.onCreateComponent())
            {
                // check list
                if (!this._popupchildlist)
                    this._popupchildlist = [];

                // add list
                this._popupchildlist.push(child);

                // return popup
                return child;
            }
        }

        // return null
        return null;
    };
    // [component.layout.panel.subgroup:create]        // Override 제외
    _pComplexComponent._createPopupCloneControl = function (child, slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/)
    {
        if (child)
        {
            // set control
            child._setControl(child._type_name);
            // set popup child
            child._setPopupContains(true);

            // clone property       // TODO: InitClone 공용처리
            child._initComponentClone(this);

            // clone property       // TODO: InitPopup 공용처리
            child._initPopupIndexLevel(slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/);

            // set overflow info    // TODO: InitOverflow 공용처리
            child._initPopupOverflow(slot, this);

            // create component     // TODO: InitClone/InitSub 공통처리후 createComponent로 변경
            if (child.onCreateComponent())
            {
                // check list
                if (!this._popupchildlist)
                    this._popupchildlist = [];

                // add list
                this._popupchildlist.push(child);

                // return popup
                return child;
            }
        }

        // return null
        return null;
    };

    // [component.layout.panel.subgroup:create]        // Override 제외
    _pComplexComponent._createPopupBandControl = function (slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/)
    {
        if (slot && this._formats)
        {
            var bandseq = 1; // this._formats._getBandSeq("detail");
            var popband = slot._getSlotTargetBand(bandseq);
            var bindidx = slot._getBindIndex();

            if (popband)
            {
                // get ctxt/bind data
                var ctxtband = popband._getCtxtBaseInfo();
                var binddata = this._getBindData(bindidx);

                var child = null;

                if (child = this._createPopupChildControl(this.createCtxtControl(ctxtband, binddata, bindidx), slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/))
                {
                    // set context itemindex
                    this._setItemIndex(child, popband._itemindex);
                    // set context iteminfo
                    this._setCtxtItemInfo(child, ctxtband, bindidx, popband._itemsubidx);
                    // set bind iteminfo
                    this._setBindItemInfo(child, binddata, bindidx, bandseq);
                    // set sublayout
                    this._setItemSubLayoutInfo(child, binddata, bindidx);

                    this._setItemIndentSize(child, this._onGetIndentSize());

                    return child;
                }
            }
        }
    };

    // [component.layout.panel.subgroup:create]        // Override 제외
    _pComplexComponent._createPopupSelfControl = function (slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/)
    {
        if (slot)
        {
            var child = this._createPopupCloneControl(new this.constructor(this._onGetPopupSelfControlName(slot, itemidx), 0, 0, 0, 0, null, null, null, null, null, null, this), slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/);

            return child;
        }
    };
    // [component.layout.panel.subgroup:getpopupname]  // 별도명칭 사용시 Override
    _pComplexComponent._onGetPopupSelfControlName = function (slot, itemidx)
    {
        if (slot)
        {
            return "popupchild" + (slot._isOverflowSlot() ? "overflow" : itemidx);
        }
    };

    // [component.layout.panel.subgroup:create]     // Override 처리
    _pComplexComponent._onCreatePopupChild = function (slot, itemidx, isbandpopup, issameindex, issamelevel, skiplevel/*, skipindex*/)
    {
        if (isbandpopup)
        {
            // create band complex component (band popup)
            return this._createPopupBandControl(slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/);
        }
        else
        {
            // create self complex component (item,ctrl popup/overflow popup)
            return this._createPopupSelfControl(slot, itemidx, issameindex, issamelevel, skiplevel/*, skipindex*/);
        }
    };
    // [component.layout.panel.subgroup:destroy]    // Override 처리
    _pComplexComponent._onDestroyPopupChild = function ()
    {
        // user prop unlink
    };
    // [component.layout.panel.subgroup:clone]      // Override 처리
    _pComplexComponent._onCloneProperities = function (source)
    {
        if (source && source instanceof nexacro.ComplexComponent)
        {
            // simple inherit
            nexacro.SimpleComponent.prototype._onCloneProperities.call(this, source);

            // bind/expr
            this._onClonePropBindExpr(source);
            // format/layout
            this._onClonePropFormatLayout(source);
            // etc
            this._onClonePropNormal(source);
        }
    };
    _pComplexComponent._onClonePropBindExpr = function (source) 
    {
        // clone property bind/expr
        var bindprop  = source._onGetBindDataProp();    if (bindprop)  this[bindprop]  = source[bindprop];
        var codeprop  = source._onGetCodeProp();        if (codeprop)  this[codeprop]  = source[codeprop];
        var levelprop = source._onGetLevelProp();       if (levelprop) this[levelprop] = source[levelprop];
        var groupprop = source._onGetGroupProp();       if (groupprop) this[groupprop] = source[groupprop];

        var dataprops = source._onGetDataProps();       for (var prop of dataprops) this[prop] = source[prop];
        var bindprops = source._onGetBindProps();       for (var prop of bindprops) this[prop] = source[prop];
    };
    _pComplexComponent._onClonePropFormatLayout = function (source) 
    {
        // clone property format/layout
        var fmtprop   = source._onGetFormatsProp();    if (fmtprop) this[fmtprop] = source[fmtprop];
        var fidprop   = source._onGetFormatIdProp();   if (fidprop) this[fidprop] = source[fidprop];

        var fexprops  = source._onGetFormatExProps();  for (var prop of fexprops) this[prop] = source[prop];
    };
    _pComplexComponent._onClonePropNormal = function (source) 
    {
        // clone property except bind/expr,format/layout
        var cloneprops = source._onGetCloneProps(); for (var prop of cloneprops) this[prop] = source[prop];
    };

    // [component.event.popup:popup]
    _pComplexComponent.on_notify_popup_onpopup = function (popupindex, startindex, startlevel, limitlevel, bindindex, itemindex, popupstyle, popupowner)
    {
        if (popupowner != this) return;
    };
    // [component.event.popup:close]
    _pComplexComponent.on_notify_popup_onclose = function (popupindex, startindex, startlevel, limitlevel, bindindex, itemindex, popupstyle, popupowner)
    {
        if (popupowner != this) return;
        if (popupstyle && popupstyle.overpopup) return;

        var panel = this._getPanel();
        if (panel)
        {
            if (panel._isGroupLeveled()) panel._setPanelSlotStatusNoAction(itemindex, nexacro._PanelSlotConst.STATUS_CLOSE);
            if (panel._isBandExtended()) panel._setPanelSlotStatusBandNoAction(itemindex, nexacro._PanelSlotConst.STATUS_CLOSE);
        }
    };

    // [component.layout.panel.subgroup.currentpopup:set]   // Override 없음
    _pComplexComponent._setCurrentPopup = function (popup)
    {
        this.__current_popupcontrol = popup;
        this.__current_popupindex   = popup ? popup._popup_index : undefined; // owner popuplist
        this.__current_pstartindex  = popup ? popup._start_index : undefined; // popup dataindex (for popup item start)
        this.__current_pfinalindex  = popup ? popup._final_index : undefined; // popup dataindex (for popup item final)
        this.__current_pstartlevel  = popup ? popup._start_level : undefined; // popup rootlevel (for popup item root : for filter start~limit level (0~0,0~1,1~3,2~3))
        this.__current_plimitlevel  = popup ? popup._limit_level : undefined; // popup leaflevel (for popup item leaf : for filter start~limit level (0~0,0~1,1~3,2~3))
        this.__current_pbindindex   = popup ? popup._pbind_index : undefined; // owner dataindex
        this.__current_pitemindex   = popup ? popup._pitem_index : undefined; // owner slotindex
        this.__current_popupstyle   = popup ? popup._popup_style : {};        // bandpopup/grouppopup
    };

    // [component.layout.panel.subgroup.popup:get]          // Override 없음
    _pComplexComponent._getPopupControl = function () { return this._getCurrentPopup(); };

    // [component.layout.panel.subgroup.popup:getcurrent]   // Override 없음
    _pComplexComponent._getCurrentPopup          = function () { return this.__current_popupcontrol; };
    _pComplexComponent._getCurrentPopupIndex     = function () { return this.__current_popupindex; };
    _pComplexComponent._getCurrentPopupStart     = function () { return this.__current_pstartindex; };
    _pComplexComponent._getCurrentPopupFinal     = function () { return this.__current_pfinalindex; };
    _pComplexComponent._getCurrentPopupLevel     = function () { return this.__current_pstartlevel; };
    _pComplexComponent._getCurrentPopupLimit     = function () { return this.__current_plimitlevel; };
    _pComplexComponent._getCurrentPopupBindIndex = function () { return this.__current_pbindindex; };
    _pComplexComponent._getCurrentPopupItemIndex = function () { return this.__current_pitemindex; };
    _pComplexComponent._getCurrentPopupStyle     = function () { return this.__current_popupstyle; };
    _pComplexComponent._isCurrentPopup           = function () { return this.__current_popupcontrol && this.__current_popupcontrol._isPopup(); };

    // [component.layout.panel.subgroup.popup:getplace]     // Override 없음
    _pComplexComponent._getPopupChildPlace = function (popup)
    {
        return this._onGetPopupChildPlace(popup);
    };
    // [component.layout.panel.subgroup.popup:getsize]      // Override 없음
    _pComplexComponent._getPopupChildSize = function (popup, basewidth, baseheight, fixwidth, fixheight)
    {
        return this._onGetPopupChildSize(popup, basewidth, baseheight, fixwidth, fixheight);
    };
    // [component.layout.panel.subgroup.popup:getposition]   // Override 없음
    _pComplexComponent._getPopupChildPosition = function (popup, basewidth, baseheight, fixleft, fixtop)
    {
        return this._onGetPopupChildPosition(popup, basewidth, baseheight, fixleft, fixtop);
    };

    // [component.layout.panel.overflow.popup:getplace]     // Override 없음
    _pComplexComponent._getPopupOverflowPlace = function (popup)
    {
        return this._onGetPopupOverflowPlace(popup);
    };
    // [component.layout.panel.overflow.popup:getsize]      // Override 없음
    _pComplexComponent._getPopupOverflowSize = function (popup, basewidth, baseheight)
    {
        return this._onGetPopupOverflowSize(popup, basewidth, baseheight);
    };
    // [component.layout.panel.overflow.popup:getposition]  // Override 없음
    _pComplexComponent._getPopupOverflowPosition = function (popup, basewidth, baseheight)
    {
        return this._onGetPopupOverflowPosition(popup, basewidth, baseheight);
    };

    // [component.layout.panel.subgroup.popup:getplace]     // 필요시 Override
    _pComplexComponent._onGetPopupChildPlace = function (popup)
    {
        return nexacro._PanelConst.GROUPING_SUBPLACE_NONE;
    };
    // [component.layout.panel.subgroup.popup:getposition]   // 필요시 Override
    _pComplexComponent._onGetPopupChildPosition = function (popup, basewidth, baseheight, fixleft, fixtop)
    {
        var org = popup._getOrigin(true);
        var cmp = popup._getAttachedComponent();
        if (org && cmp)
        {
            // get extrainfo
            var indent = this._onGetItemIndentSize(cmp);

            // calc position
            var win = this._getWindow()
            var winh = nexacro._getMainWindowHeight(win);
            var winw = nexacro._getMainWindowWidth(win);

            var orgp = nexacro._getElementPositionInFrame(org.getElement());
            var orgh = org.getPixelHeight();
            var orgw = org.getPixelWidth();

            var comh = cmp._getContextHeight(this._getClientHeight());
            var comw = cmp._getContextWidth(this._getClientWidth());

            var posl = indent ? (0 + indent[0]) : 0;
            var post = orgh;

            if ((orgp.y + orgh + comh > winh) && (orgp.y - comh >= 0)) post = -comh;
            if ((orgp.x + orgw + comw > winw) && (orgp.x - comw >= 0)) posl = -comw;

            return [fixleft ?? posl, fixtop ?? post];
        }
        else
        {
            return [fixleft ?? 0, fixtop ?? 0];
        }
    };
    // [component.layout.panel.subgroup.popup:getsize]      // 필요시 Override
    _pComplexComponent._onGetPopupChildSize = function (popup, basewidth, baseheight, fixwidth, fixheight)
    {
        var org = popup._getOrigin(true);
        var cmp = popup._getAttachedComponent();
        if (cmp && cmp._getContextSize)
        {
            var ret;

            if (org)
                ret = cmp._getContextSize(this._getClientWidth(), this._getClientHeight(), org.getPixelWidth(), org.getPixelHeight());
            else
                ret = cmp._getContextSize(this._getClientWidth(), this._getClientHeight());

            return [fixwidth ?? ret[0], fixheight ?? ret[1]];
        }
        else
        {
            return [fixwidth ?? this.getPixelWidth(), fixheight ?? this.getPixelHeight()];
        }
    };

    // [component.layout.panel.overflow.popup:getplace]     // 필요시 Override
    _pComplexComponent._onGetPopupOverflowPlace = function (popup)
    {
        var iside = this._isOverflowCtrInside();
        var hbase = iside ? nexacro._PanelConst.GROUPING_SUBPLACE_BASE_HORZ_ORIGIN : nexacro._PanelConst.GROUPING_SUBPLACE_BASE_HORZ_ROOT;
        var vbase = iside ? nexacro._PanelConst.GROUPING_SUBPLACE_BASE_VERT_ORIGIN : nexacro._PanelConst.GROUPING_SUBPLACE_BASE_VERT_ROOT;

        // check overflowpopup direction
        return this._isRowFirst()
            ? (hbase | nexacro._PanelConst.GROUPING_SUBPLACE_BASE_VERT_ROOT | nexacro._PanelConst.GROUPING_SUBPLACE_VERT_DOWN      | nexacro._PanelConst.GROUPING_SUBPLACE_HORZ_RIGHT)
            : (vbase | nexacro._PanelConst.GROUPING_SUBPLACE_BASE_HORZ_ROOT | nexacro._PanelConst.GROUPING_SUBPLACE_VERT_BOTTOM    | nexacro._PanelConst.GROUPING_SUBPLACE_HORZ_NEXT);
    };
    // [component.layout.panel.overflow.popup:getposition]   // 필요시 Override
    _pComplexComponent._onGetPopupOverflowPosition = function (popup, basewidth, baseheight)
    {
        return this._onGetPopupChildPosition(popup, basewidth, baseheight);
    };
    // [component.layout.panel.overflow.popup:getsize]      // 필요시 Override
    _pComplexComponent._onGetPopupOverflowSize = function (popup, basewidth, baseheight)
    {
        return this._onGetPopupChildSize(popup, basewidth, baseheight);
    };

    //===============================================================
    // nexacro.ComplexComponent : Layout/Selector
