    // [component.layout.format.child:recalc]       // ComplexComponent에서 별도처리시 Override
    _pComplexComponent._onRecalcFormatChildLayout = function (reset)
    {
        var ctxts = this._ctxtdata;

        if (ctxts)
        {
            var child = this._getChildren();

            /*
            if (isRowCol)
            {
                // Formats Recalc Child RowCol
                for (var item of child)
                {
                    if (item && item._update_position)
                    {
                        item._update_position();
                    }
                }
            }
            else
            */
            {
                // Formats Recalc Child Position
                for (var item of child)
                {
                    if (item && item._update_position)
                    {
                        item._update_position();
                    }
                }
            }
            
            if (!this._is_child || !this._p_childalign) return;

            function _setnil(chknil, nilv)
            {
                return nexacro._isNull(chknil) ? nilv : null;
            }

            // align
            var A = this._getAlignChildList();

            for (var a of A)
            {
                if (!a) continue;

                var s = a.alignchd;
                switch (a.alignval)
                {
                    case "left"         : var l = 100000;                                   for (var c of s) if (c) { l = Math.min(l, c.getOffsetLeft()); }                                              var L = l;                    for (var c of s) if (c) {                                                                   c.move(L,                       c.top,                  c.width, c.height, _setnil(c.width,c.right), c.bottom                  ); } break;
                    case "top"          : var t = 100000;                                   for (var c of s) if (c) { t = Math.min(t, c.getOffsetTop());  }                                              var T = t;                    for (var c of s) if (c) {                                                                   c.move(c.left,                  T,                      c.width, c.height, c.right,                  _setnil(c.height,c.bottom)); } break;
                    case "right"        : var             r = 0, PW = this._basis_width;    for (var c of s) if (c) {                                            r = Math.max(r, c.getOffsetRight());  } var R = Math.max(PW - r, 0);  for (var c of s) if (c) {                                                                   c.move(_setnil(c.width,c.left), c.top,                  c.width, c.height, R,                        c.bottom                  ); } break;
                    case "bottom"       : var             b = 0, PH = this._basis_height;   for (var c of s) if (c) {                                            b = Math.max(b, c.getOffsetBottom()); } var B = Math.max(PH - b, 0);  for (var c of s) if (c) {                                                                   c.move(c.left,                  _setnil(c.width,c.top), c.width, c.height, c.right,                  B                         ); } break;
                    case "center"       : var l = 100000, r = 0, PW = this._basis_width;    for (var c of s) if (c) { l = Math.min(l, c.getOffsetLeft()),        r = Math.max(r, c.getOffsetRight());  } var W = Math.min(r - l, PW);  for (var c of s) if (c) { var L = Math.max(Math.floor((W - c.getOffsetWidth())  / 2), 0);   c.move(L + l,                   c.top,                  c.width, c.height, _setnil(c.width,c.right), c.bottom                  ); } break;
                    case "middle"       : var t = 100000, b = 0, PH = this._basis_height;   for (var c of s) if (c) { t = Math.min(t, c.getOffsetTop()),         b = Math.max(b, c.getOffsetBottom()); } var H = Math.min(b - t, PH);  for (var c of s) if (c) { var T = Math.max(Math.floor((H - c.getOffsetHeight()) / 2), 0);   c.move(c.left,                  T + t,                  c.width, c.height, c.right,                  _setnil(c.height,c.bottom)); } break;
                    case "centerleft"   : var l = 100000, w = 0, PW = this._basis_width;    for (var c of s) if (c) { l = Math.min(l, c.getOffsetLeft()),        w = Math.max(w, c.getOffsetWidth());  } var W = Math.min(w, PW);      for (var c of s) if (c) { var L = Math.max(Math.floor((W - c.getOffsetWidth())  / 2), 0);   c.move(L + l,                   c.top,                  c.width, c.height, _setnil(c.width,c.right), c.bottom                  ); } break;
                    case "middletop"    : var t = 100000, h = 0, PH = this._basis_height;   for (var c of s) if (c) { t = Math.min(t, c.getOffsetTop()),         h = Math.max(h, c.getOffsetHeight()); } var H = Math.min(h, PH);      for (var c of s) if (c) { var T = Math.max(Math.floor((H - c.getOffsetHeight()) / 2), 0);   c.move(c.left,                  T + t,                  c.width, c.height, c.right,                  _setnil(c.height,c.bottom)); } break;
                    case "centerright"  : var r = 100000, w = 0, PW = this._basis_width;    for (var c of s) if (c) { r = Math.min(r, PW - c.getOffsetRight()),  w = Math.max(w, c.getOffsetWidth());  } var W = Math.min(w, PW);      for (var c of s) if (c) { var R = Math.max(Math.floor((W - c.getOffsetWidth())  / 2), 0);   c.move(_setnil(c.width,c.left), c.top,                  c.width, c.height, R + r,                    c.bottom                  ); } break;
                    case "middlebottom" : var b = 100000, h = 0, PH = this._basis_height;   for (var c of s) if (c) { b = Math.min(b, PH - c.getOffsetBottom()), h = Math.max(h, c.getOffsetHeight()); } var H = Math.min(h, PH);      for (var c of s) if (c) { var B = Math.max(Math.floor((H - c.getOffsetHeight()) / 2), 0);   c.move(c.left,                  _setnil(c.width,c.top), c.width, c.height, c.right,                  B + b                     ); } break;
                }
            }

            // update scroll
            this._updateChildScrollInfo(true);
        }
    };
    // [component.layout.format.items:recalc]       // ComplexComponent에서 별도처리시 Override
