    // [component.layout.container:childalign]      // ComplexComponent에서 별도처리시 Override
    _pComplexComponent.set_childalign = function (v)  // childalign="left|center|right|top|middle|bottom:childid1[,childid2][ left|center|right|top|middle|bottom:childid1[,childid2]]"
    {
        if (this._p_childalign != v)
            this._p_childalign = v

        this._on_apply_childalign();
    };

    // TODO : Component Flex로 변경
    _pComplexComponent._on_apply_childalign = function ()
    {
        var alignlst = this._alignlst = {};

        this._alignlst["values"] = [];
        this._alignlst["setted"] = false;

        if (!this._p_childalign) return;

        var alignarr = this._p_childalign.split(' ');

        for (var v of alignarr)
        {
            var alignatt = v.split(':')
            var alignval = alignatt.length > 0 ? alignatt[0] : "";
            var aligngrp = alignatt.length > 1 ? alignatt[1].split(',') : [];

            alignlst.values.push({ alignval: alignval, aligngrp: aligngrp, alignchd: [] });
        }
    };

    _pComplexComponent._getAlignChildList = function ()
    {
        if (!this._alignlst) this._on_apply_childalign();

        var alignlst = this._alignlst;

        if (!alignlst.setted)
        {
            for (var a of alignlst.values)
            {
                if (!a) continue;

                if (a.aligngrp.length <= 0)
                {
                    a.alignchd = this._getChildren();
                }
                else
                {
                    for (var c of a.aligngrp) a.alignchd.push(this._findChild(c));
                }
            }

            alignlst.setted = true;
        }

        return alignlst.values;
    };

    _pComplexComponent.on_apply_fittocontents = function (skipupdateposition)
    {
        var panel = this._panel;

        if (panel)
            panel._setFitToContentType(this._getFitToContentType());

        nexacro.SimpleComponent.prototype.on_apply_fittocontents.call(this, skipupdateposition);
    };

    //===============================================================
    // nexacro.ComplexComponent : Ctrl (Child+Items)
