    // [Complex Component 처리]
    // Child와 Items 공통 Interface


    // TODO : Component Abstract Type으로 변경
    // [component.layout.ctrl:childtype]            // ComplexComponent에서 별도처리시 Override
    _pComplexComponent.set_childtype = function (v) // childtype="ctrlid[,ctrlid]" childtype="make:ctrlid[,ctrlid] skip:ctrlid[,ctrlid]"
    {
        if (this._p_childtype != v)
            this._p_childtype = v

        this._on_apply_childtype();
    };
    _pComplexComponent._on_apply_childtype = function ()
    {
        this._setChildTypeList(this._p_childtype);
    };
    _pComplexComponent._setChildTypeList = function (typelist)
    {
        var typelst = this._typelst = { maketypes: [] }; // { maketypes : [], skiptype : [] };

        if (!typelist) return;

        /*
        var make = typelist.split(' :');
        var skip = typelist.split(' :');
        */

        var maketypearr = typelist.split(',');

        for (var v of maketypearr)
        {
            if (v) typelst.maketypes.push(v);
        }

        /*
        var skiptypearr = typelist.split(',');

        for (var v of skiptypearr)
        {
            if (v) typelst.skiptypes.push(v);
        }
        */
    };
    _pComplexComponent._getChildTypeListMake = function () { this._typelst ? this._typelst.maketypes : null; };
    _pComplexComponent._getChildTypeListSkip = function () { this._typelst ? this._typelst.skiptypes : null; };

    // [component.layout.ctrl:getfirsteditable]         // ComplexComponent에서 별도처리시 Override (하위에서 옮겨놓음)
    _pComplexComponent._getFirstEditableCtrl = function ()
    {
        var info = { rowidx: this._DEFAULT_ROWINDEX, bandidx: this._DEFAULT_BANDINDEX, ctrlidx: this._DEFAULT_CTRLINDEX, item: null, ctrl: null };

        var rowcnt = this._getBindCount();
        if (rowcnt > 0)
        {
            // find row, ctrl : first -> last
            for (var i = 0; i < rowcnt; i++)
            {
                var item = this._getItem(0);
                if (item)
                {
                    var ctrl = this._findEditableCtrl(item, 0, 1);
                    if (ctrl)
                    {
                        info.rowidx = ctrl._rowidx;
                        info.bandidx = ctrl._bandidx;
                        info.ctrlidx = ctrl._ctrlidx;
                        info.item = item;
                        info.ctrl = ctrl;
                        break;
                    }
                }
            }
        }

        return info;
    };
    // [component.layout.ctrl:getlasteditable]          // ComplexComponent에서 별도처리시 Override (하위에서 옮겨놓음)
    _pComplexComponent._getLastEditableCtrl = function ()
    {
        var info = { row: this._DEFAULT_ROWINDEX, band: this._DEFAULT_BANDINDEX, ctrl: this._DEFAULT_CTRLINDEX };

        var rowcnt = this._getBindCount();
        if (rowcnt > 0)
        {
            // find row, ctrl : last -> first
            for (var i = rowcnt - 1; i >= 0; i--)
            {
                var items = this._getItem(i);
                if (items)
                {
                    var ctrl, lastctrl;
                    if (nexacro._isArray(items))
                    {
                        for (var j = items.length - 1; j >= 0; j--)
                        {
                            var item = items[j];
                            if (j > 0)
                            {
                                if (!this._getPanelSubBandMultiExtend(item._rowidx)) // detail item collapse
                                    continue;
                            }
                            if (item && (lastctrl = item._getLastChild()))
                            {
                                if (lastctrl && (ctrl = this._findEditableCtrl(item, lastctrl._ctrlidx, -1)))
                                    break;
                            }
                        }
                    }
                    else
                    {
                        if (lastctrl = items._getLastChild())
                        {
                            ctrl = this._findEditableCtrl(items, lastctrl._ctrlidx, -1);
                        }
                    }

                    if (ctrl)
                    {
                        info.row = ctrl._rowidx;
                        info.band = ctrl._bandidx;
                        info.ctrl = ctrl._ctrlidx;
                        break;
                    }
                }
            }
        }

        return info;
    };
    // [component.layout.ctrl:findeditable]           // ComplexComponent에서 별도처리시 Override (하위에서 옮겨놓음)
    _pComplexComponent._findEditableCtrl = function (item, from_ctrlidx, dir)
    {
        var i, n;
        var ctrl = null;

        if (nexacro._isArray(item))
        {
            for (i = 0, n = item.length; i < n; i++)
            {
                if (i > 0)
                {
                    from_ctrlidx = (dir == 1) ? 0 : item._getLastChild() ? item._getLastChild()._ctrlidx : 0;

                    if (item[i] && !this._getPanelSubBandMultiExtend(item[i]._rowidx)) // detail item collapse
                        continue;
                }

                if (item[i] && (ctrl = this._findEditableCtrl(item[i], from_ctrlidx, dir)))
                    break;
            }
        }
        else
        {
            var ctrls = this._getItemCtrls(item);
            if (ctrls)
            {
                switch (dir)
                {
                    case -1:
                        for (i = from_ctrlidx; i >= 0; i--)
                        {
                            var c = ctrls[i];
                            if (c && c._hasEditor && c._hasEditor())
                            {
                                ctrl = c;
                                break;
                            }
                        }
                        break;
                    case 1:
                        for (i = from_ctrlidx, n = ctrls.length; i < n; i++)
                        {
                            var c = ctrls[i];
                            if (c && c._hasEditor && c._hasEditor())
                            {
                                ctrl = c;
                                break;
                            }
                        }
                        break;
                }
            }
        }

        return ctrl;
    };
    // [component.layout.ctrl:ramaineditable]           // ComplexComponent에서 별도처리시 Override (하위에서 옮겨놓음)
    _pComplexComponent._remainEditableCtrl = function (dir)
    {
        // 현재 select 시점 기준으로 front / back 방향으로 움직일 Ctrl이 있는지 여부 판단
        var sel = this.getSelect();
        var rowcnt = this._getBindCount();

        var item;
        var items = this._getItem(sel.row);
        if (items)
        {
            var item, ctrl, i;

            var rowidx = sel.row;
            var bandidx = sel.band;
            var ctrlidx = sel.ctrl < 0 ? 0 : sel.ctrl;

            switch (dir)
            {
                // 역방향
                case -1:
                    item = nexacro._isArray(items) ? items[bandidx >= 0 ? sel.band : 0] : items;
                    ctrl = this._findEditableCtrl(item, ctrlidx - 1, dir);

                    if (!ctrl)
                    {
                        for (i = rowidx; i >= 0; i--)
                        {
                            if (bandidx > 0)
                            {
                                bandidx--;
                            }
                            else
                            {
                                rowidx--;

                                // detail expand check
                                if (this._getPanelSubBandMultiExtend(rowidx))
                                    bandidx = this._getPanelSlotCount() - 1;
                                else
                                    bandidx = 0;
                            }

                            if (item = this._getCurrentItem(rowidx, bandidx))
                            {
                                var ctrls = this._getItemCtrls(item);
                                ctrlidx = ctrls ? ctrls.length - 1 : 0;
                                ctrl = this._findEditableCtrl(item, ctrlidx, -1);
                            }

                            if (ctrl) break;
                        }
                    }
                    break;
                // 순방향
                case 1:
                    item = nexacro._isArray(items) ? items[bandidx >= 0 ? sel.band : 0] : items;
                    ctrl = this._findEditableCtrl(item, ctrlidx + 1, dir);

                    if (!ctrl)
                    {
                        for (i = rowidx; i < rowcnt; i++)
                        {
                            if (bandidx < this._getPanelSlotCount() - 1 && this._getPanelSubBandMultiExtend(rowidx))    // detail expand check
                            {
                                bandidx++;
                            }
                            else
                            {
                                rowidx++;
                                bandidx = 0;
                            }

                            if (item = this._getCurrentItem(rowidx, bandidx))
                            {
                                ctrlidx = 0;
                                ctrl = this._findEditableCtrl(item, ctrlidx, 1);
                            }

                            if (ctrl) break;
                        }
                    }
                    break;
            }

            if (ctrl)
                return true;
        }

        return false;
    };

    // [component.layout.ctrl:getitemctrls]           // ComplexComponent에서 별도처리시 Override
    _pComplexComponent._getItemCtrls = function (item)
    {
        var ctrls = item._children;

        if (ctrls && ctrls.length)
        {
            //    if (ctrls[0] instanceof nexacro.Component)
            return ctrls;
        }

        return null;
    };
    // [component.layout.ctrl:getcurrent]           // ComplexComponent에서 별도처리시 Override
    _pComplexComponent._getCurrentCtrl = function (rowidx, subidx, ctrlidx)
    {
        var currselect = this.getSelect();
        var curctrl = (ctrlidx != null) ? ctrlidx : currselect.ctrl;
        var item = this._getCurrentItem(rowidx, subidx);
        var ctrl = null;

        if (item)
        {
            var ctrls = this._getItemCtrls(item);

            if (ctrls)
            {
                if (typeof (curctrl) == "string")
                {
                    for (var i = 0, n = ctrls.length; i < n; i++)
                    {
                        if (ctrls[i].id == curctrl)
                        {
                            ctrl = ctrls[i];
                            break;
                        }
                    }
                }
                else
                {
                    ctrl = ctrls[curctrl];
                }
            }
        }
        return ctrl;
    };

    //===============================================================
    // nexacro.ComplexComponent : Child/Create,Destroy
    //===============================================================

    // [Complex Component 처리]
    // 복합구성을 비반복적인 Logic으로 구성처리
    // Items와는 별도로 Children로 관리되며
    // 각 개별 control property를 가지게 된다.


    // [component.layout.child:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getChildren = function ()
    {
        return this._children;
    };
    // [component.layout.child:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getChild = function (childindex)
    {
        return this._children ? this._children[childindex] : null;
    };
    // [component.layout.child:get]                 // 필요시 override
    _pComplexComponent._getLeadChild = function ()
    {
        return this._leadchild ? this._leadchild : (this._children && this._children.length ? this._children[0] : null);
    };
    _pComplexComponent._getCurrChild = function ()
    {
        return this._currchild;
    };
    _pComplexComponent._getPrevChild = function (curr, focus, edit)
    {
        var children = this._children; if (!children || !curr) return null;
        var curridx = children.indexOf(curr);

        for (var i = curridx - 1; i >= 0; i--)
        {
            var child = children[i]; if (!child) continue;

            if (!edit && !focus)
                return child;

            var focusable = !focus || child._isFocusAcceptable();
            var editable = !edit || child._isEditableComponent();

            if (focusable && editable)
                return child;
        }
    };
    _pComplexComponent._getNextChild = function (curr, focus, edit)
    {
        var children = this._children; if (!children || !curr) return null;
        var curridx = children.indexOf(curr);

        for (var i = curridx + 1, l = children.length; i < l; i++)
        {
            var child = children[i]; if (!child) continue;

            if (!edit && !focus)
                return child;

            var focusable = !focus || child._isFocusAcceptable();
            var editable = !edit || child._isEditableComponent();

            if (focusable && editable)
                return child;
        }
    };
    _pComplexComponent._getLastChild = function ()
    {
        var children = this._children;
        if (children)
        {
            return children[children.length - 1];
        }

        return null;
    };
    // [component.layout.child:set]                 // 필요시 override
    _pComplexComponent._setLeadChild = function (child)
    {
        this._leadchild = child;
    };
    _pComplexComponent._setCurrChild = function (child)
    {
        this._currchild = child;
    };

    // [component.layout.child:getareawidth]        // 필요시 override     
    _pComplexComponent._onGetChildAreaWidth = function ()
    {
        return this._getClientWidth();
    };

    // [component.layout.child:getareaheight]       // 필요시 override
    _pComplexComponent._onGetChildAreaHeight = function ()
    {
        return this._getClientHeight();
    };

    // [component.layout.child.collection:add]      // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._addChildCollection = function (childid, child)
    {
        if (this._childlst) this._childlst[childid] = child;
    };
    // [component.layout.child.collection:find]     // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._findChildCollection = function (childid)
    {
        return this._childlst ? this._childlst[childid] : null;
    };
    // [component.layout.child.collection:find]     // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._findChildCollectIndex = function (child)
    {
        return this._children ? this._children.indexOf(child) : -1;
    };
    // [component.layout.child:find]                // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._findChild = function (childid)
    {
        return this[childid] ?? this._findChildCollection(childid);
    };
    // [component.layout.child:find]                // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._seekChild = function (childid)
    {
        var child = this._findChild(childid);

        return child && child._p_visible ? child : null;
    };
    // [component.layout.child:find]                // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._findChildIndex = function (child)
    {
        return this._findChildCollectIndex(child);
    };
    _pComplexComponent._findItemChildIndex = function (item, child)
    {
        return (item && item._findChildCollectIndex) ? item._findChildCollectIndex(child) : this._DEFAULT_CTRLINDEX;
    };
    _pComplexComponent._getChildId = function (child)
    {
        return child ? child.id ? child.id : child.name : "";
    };
    _pComplexComponent._getItemChildId = function (item, child)
    {
        return (item && item._getChildId) ? item._getChildId(child) : "";
    };

    // [component.layout.child:create]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._createChild = function ()
    {
        if (this._is_child && this._children)
        {
            /* not allowed
            if (this._is_databind)
            {
                this._createBindChild(this._getBindData(), this._getCtxtData());
            }
            else
            */
            {
                this.onCreateChild(this._getCtxtData());
            }
        }
    };
    // [component.layout.child:created]             // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._createdChild = function (window)
    {
        if (this._is_child && this._children)
        {
            // crated child
            this.onCreatedChild(window);
        }
    };
    // [component.layout.child:update]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._updateChild = function (child)
    {
        if (this._is_child && this._children)
        {
            this.onUpdateChild(child);
        }
    };
    // [component.layout.child:destory]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._destroyChild = function ()
    {
        if (this._is_child && this._children)
        {
            // destroy child
            this.onDestroyChild();

            // clear child (ctxt)
            this._clearChild();
        }
    };
    // [component.layout.child:clear]                   // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._clearChild = function ()
    {
        if (this._is_child && this._children)
        {
            // user unlink child : 별도 제공하지 않고 _onDestroyChild 사용
            // this._onClearChild();

            if (this._alignlst)
            {
                this._alignlst = null;
            }
            if (this._childlst)
            {
                this._childlst = {};
            }

            // TODO : Detach 우선 처리후 Delete는 Idle 에서 처리

            var child = this._children;
            var count = child.length;

            for (var i = count - 1; i >= 0; i--)
            {
                if (child[i])
                {
                //  child[i].onClearChild();

                    child[i].destroy();
                    delete child[i];
                //  child[i] = null;
                }
            }

            this._children.length = 0;
            this._children = [];
        }
    };

    // [component.layout.child:create]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent.createChildControl = function (child)
    {
        if (child)
        {
            // set control
            child._setControl(child._type_name);

            // create component
            if (child.createComponent(true))
            {
                // add children
                this._children.push(child);
            }

            // return child
            return child;
        }

        // return null
        return null;
    };
    // [component.layout.child:create nc]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent.createNCChild = function (child)
    {
        if (child)
        {
            child._is_nc_control = true;

            if (child.createComponent(true))
            {
                return child;
            }
        }

        return null;
    };
    // [component.layout.child:create nc control]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent.createNCChildControl = function (child)
    {
        if (child)
        {
            // set nccontrol
            child._is_nc_control = true;
            // set control
            child._setControl();

            // create component
            if (child.createComponent(true))
            {
                // add children
                // this._ncchildren.push(child);

                // return child
                return child;
            }
        }

        // return null
        return null;
    };
    // [component.layout.child:create clone]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent.createCloneChildControl = function (child)
    {
        if (child)
        {
            // set control
            child._setControl(child._type_name);

            // clone property       // TODO: InitClone 공용처리
            child._initComponentClone(this);

            // create component     // TODO: InitClone 공통처리후 createComponent로 변경
            if (child.onCreateComponent())
            {
                // add children
                this._children.push(child);

                // return child
                return child;
            }
        }

        // return null
        return null;
    };
    // [component.layout.child.ctxt:create]         // override는 basic component내에서만 가급적 최소화
    _pComplexComponent.createChildCtxtControl = function (ctxt, bind)
    {
        if (ctxt)
        {
            // get child context
            var ctxtchild = ctxt._items;
            if (ctxtchild)
            {
                var i, n;
                var child;
                var childs = [];
                var maketype = this._getChildTypeListMake();
            //  var skiptype = this._getChildTypeListSkip();

                if (nexacro._isArray(ctxtchild))
                {
                    for (i = 0, n = ctxtchild.length; i < n; i++)
                    {
                        var ctxtchd = ctxtchild[i];

                        if (maketype && maketype.indexOf(ctxtchd._typeenum) <  0) continue;
                    //  if (skiptype && skiptype.indexOf(ctxtchd._typeenum) >= 0) continue;
                            
                        // create ctxt component --> childid : ctxt._id (no seq)
                        child = this.createCtxtControl(ctxtchd, bind, i, true);

                        // create item component
                        childs.push(this.createChildControl(child));
                    }

                    return childs;
                }
                else
                {
                    if (maketype && maketype.indexOf(ctxtchild._typeenum) <  0) return null;
                //  if (skiptype && skiptype.indexOf(ctxtchild._typeenum) >= 0) return null;

                    // create ctxt component --> childid : ctxt._id (no seq)
                    child = this.createCtxtControl(ctxtchild, bind);

                    // create item component
                    return this.createChildControl(child);
                }
            }
        }

        return null;
    };

    // [component.layout.child:created]             // child형은 가급적 override하여 처리
    _pComplexComponent.onCreatedChild = function (window)
    {
    //  if (this._is_child && this._children)
        {
            var child = this._getChildren();
            var count = child ? child.length : 0;

            for (var i = 0; i < count; i++)
            {
            //  child[i].onCreated(window);
                child[i].on_created(window);
            }
        }
    };

    // [component.layout.child:eventahandler]             // child형은 가급적 override하여 처리
    _pComplexComponent._setChildEventHandler = function (eventid, handlerfunc, handlertarget)
    {
        // init band
        var children = this._children;

        if (children)
        {
            for (var i = 0, l = children.length; i < l; i++)
            {
                var child = children[i];

                if (child)
                    child._setEventHandler(eventid, handlerfunc, handlertarget);
            }
        }
    };

    // [하위 Component 처리]
