    //===============================================================
    // nexacro.ComplexComponent : Items
    //===============================================================

    // [Complex Component 처리]
    // 복합구성을 InnerBind List형과 같은 반복형 Logic으로 처리
    // Childs와는 별도로 Items로 관리됨 (통합하면 안될까??)
    // Items는 Format/Bind/Repeat 3가지로 제공됨
    //   - Format : Formats Interface로 Item을 생성
    //   - Bind   : Bind Interface로 Item을 생성
    //   - Repeat : Repeat Interface로 Item을 생성

    // [component.layout.items:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItems = function ()
    {
        return this._items;
    };
    // [component.layout.items:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItem = function (itemindex, partcreate)
    {
        var items = this._getItems();
        var count = items ? items.length : 0;

        if (items && count)
        {
            // return var
            var ret;

            // loop var
            var i;

            // loop cnt
            var n;

            // function var
            var headcount = this._getItemHeadCount();
            var tailcount = this._getItemTailCount();
            var bodycount = this._getItemBodyCount();

            var c = itemindex * bodycount + headcount;

            if (itemindex >= 0 && itemindex < count)
            {
                if (this._use_partitem)
                {
                    if (c >= count || !items[c])
                    {
                        if (partcreate)
                        {
                            this._createPartItem(itemindex);
                        }
                    }

                    if (bodycount > 1)
                    {
                        ret = new Array(bodycount);
                        for (i = 0, n = bodycount; i < n; i++, c++)
                        {
                            ret[i] = items[c];
                        }

                        return ret;
                    }
                    else
                    {
                        return items[c];
                    }
                }
                else
                {
                    if (bodycount > 1)
                    {
                        ret = new Array(bodycount);
                        for (i = 0, n = bodycount; i < n; i++, c++)
                        {
                            ret[i] = items[c];
                        }

                        return ret;
                    }
                    else
                    {
                        return items[c];
                    }
                }
            }
            if (itemindex == -1 && headcount)
            {
                if (headcount > 1)
                {
                    ret = new Array(headcount);
                    for (i = 0, n = headcount; i < n; i++)
                    {
                        ret[i] = items[i];
                    }

                    return ret;
                }
                else
                {
                    return items[0];
                }
            }
            if (itemindex == -2 && tailcount)
            {
                c = count - tailcount;

                if (tailcount > 1)
                {
                    ret = new Array(tailcount);
                    for (i = 0; c < count; i++, c++)
                    {
                        ret[i] = items[c];
                    }

                    return ret;
                }
                else
                {
                    return items[c];
                }
            }
        }

        return null;
    };
    // [component.layout.items:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItembyBindIndex = function (itemindex, partcreate)
    {
        return this._getItem(this._getItemIndexbyBindindex(itemindex), partcreate);
    }
    // [component.layout.items:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItemSingle = function (itemindex)
    {
        var items = this._getItems();
        var count = items.length;

        if (items && count)
        {
            var headcount = this._getItemHeadCount();
            var tailcount = this._getItemTailCount();
            var bodycount = this._getItemBodyCount();

            var c = -1

            if (itemindex >=  0 && bodycount) c = itemindex * bodycount + headcount;
            if (itemindex == -1 && headcount) c = 0;
            if (itemindex == -2 && tailcount) c = count - this._tail_count;

            if (c >= 0 && c < count)
            {
                return items[c];
            }
        }

        return null;
    };
    _pComplexComponent._getItemAvailable = function (itemindex)
    {
        var item = this._getItem(itemindex);
        if (item && item._p_visible && item._p_enable && item.getOffsetWidth() > 0 && item.getOffsetHeight() > 0)
        {
            return item;
        }

        return null;
    }
    _pComplexComponent._getCurrentItem = function (rowidx)
    {
        if (rowidx === undefined)
        {
            rowidx = this._getCurrentSelectItemIndex();
        }
        if (rowidx !== undefined)
        {
            return this._getItem(rowidx);
        }
    }

    // 확인 : bindindex-->itemindex 변환

    // [component.layout.items:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItemIndexbyBindIndex = function (bindindex, nearlevel)
    {
        if (bindindex < 0) return bindindex;

        var panel = this._getPanel();
        if (panel)
        {
            // get itemindex
            var idx = panel._getPanelItemIndexbyBindIndex(bindindex);

            if (!nearlevel || idx >= 0) return idx;

            // get near upper/lower level itemindex
            return panel._getPanelNearLevelItemIndexbyBindIndex(bindindex, this._bringLevelBindValue(bindindex));
        }

        return -9;
    };

    _pComplexComponent._getItemSelectPathByLevel = function (itemselect)
    {
        if (!nexacro._isNull(itemselect) && !nexacro._isArray(itemselect) && 
            this._is_levelbind && this._getBindRootLevel() < this._getBindLeafLevel())
        {
            var panel = this._getPanel();
            if (panel)
            {
                // get bindindex
                var bindindex = panel._getPanelItemIndexbyBindIndex(this._onGetSelectBindIndex(itemselect));

                // get path level itemindex
                var pathindex = panel._getPanelPathLevelItemIndexbyBindIndex(bindindex, this._bringLevelBindValue(bindindex));

                // return selectobject array
                return pathindex.map((x) => this._onGetSelectArgument(x, -1, -1, undefined, false)).reverse();
            }
        }

        return itemselect;
    };

    _pComplexComponent._getBindIndexByItemIndex = function (itemindex)
    {
        var item = this._getItem(itemindex);
        if (item)
            return this._getItemBindIndex(item);

        return itemindex;
    };

    _pComplexComponent._getItemChildByIndex = function (itemindex, subindex, childindex)
    {
        var item = this._getItem(itemindex);
        if (item)
        {
            if (nexacro._isArray(item))
            {
                item = item[subindex];
            }

            if (item)
            {
                if (item._is_child && item._getChild)
                {
                    return item._getChild(childindex);
                }

                if (item._is_items && item._getItem)
                {
                    return item._getItem(childindex);
                }
            }
        }

        return null;
    };

    _pComplexComponent._getItemChildById = function (itemindex, subid, childid)
    {
        var item = this._getItem(itemindex);
        if (item)
        {
            if (nexacro._isArray(item))
            {
                for (var i = 0; i < item.length; i++)
                {
                    if (item[i] && item[i]._band == subid)
                    {
                        item = item[i]; break;
                    }
                }
            }

            if (item)
            {
                if (item._is_child && item._getChild)
                {
                    return item._findChild(childid);
                }

                //if (item._is_items && item._getItem)
                //return item._getItem(childid);
            }
        }

        return null;
    };

    _pComplexComponent._getItemChildInPopup = function (itemindex, subindex, childindex)
    {
        var slot = this._getPanelSlot(itemindex);
        if (slot)
        {
            var popup = slot._getSlotPopup();
            if (popup)
            {
                var comp = popup._getAttachedComponent();
                if (comp && comp._getChild)
                {
                    return comp._getChild(childindex);
                }
            }
        }

        return null;
    };

    // [component.layout.items:get]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getRawItem = function (itemindexset)
    {
        if (itemindexset.length)
        {
            // TODO : more 2 depth
            return this._getRawItemInItems(this._getItem(itemindexset[0]), itemindexset[1]);
        }
        else
        {
            return this._getRawItemInItems(this._getItem(itemindexset), 0);
        }
    };
    _pComplexComponent._getRawItemInItems = function (items, subindex)
    {
        var count = items ? items.length : 0;
        if (count)
        {
            if (subindex && subindex < count)
            {
                return items[subindex];
            }
            else
            {
                return items[0];
            }

        }
        return items;
    };

    // [component.layout.items:del]                 // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._delItem = function (itemindex, destroy)
    {
        var items = this._getItems();
        var count = items.length;

        if (items && count)
        {
            // loop var
            var i;

            // loop cnt
            var n;

            // function var
            var headcount = this._getItemHeadCount();
            var tailcount = this._getItemTailCount();
            var bodycount = this._getItemBodyCount();

            var c = itemindex * bodycount + headcount;

            if (itemindex >= 0 && itemindex < count)
            {
                if (bodycount > 1)
                {
                    for (i = 0, n = bodycount; i < n; i++, c++)
                    {
                        if (items[c])
                        {
                            if (items[c].destroy)
                            {
                                items[c].destroy();
                            }
                            items[c] = null;
                        }
                    }
                }
                else
                {
                    if (items[c])
                    {
                        if (items[c].destroy)
                        {
                            items[c].destroy();
                        }
                        items[c] = null;
                    }
                }

                return bodycount;
            }
            if (itemindex == -1 && headcount)
            {
                c = 0;

                if (headcount > 1)
                {
                    for (i = 0, n = headcount; i < n; i++, c++)
                    {
                        if (items[c])
                        {
                            if (items[c].destroy)
                            {
                                items[c].destroy();
                            }
                            items[c] = null;
                        }
                    }
                }
                else
                {
                    if (items[c])
                    {
                        if (items[c].destroy)
                        {
                            items[c].destroy();
                        }
                        items[c] = null;
                    }
                }

                return headcount;
            }
            if (itemindex == -2 && tailcount)
            {
                c = count - tailcount;

                if (tailcount > 1)
                {
                    for (i = 0; c < count; i++, c++)
                    {
                        if (items[c])
                        {
                            if (items[c].destroy)
                            {
                                items[c].destroy();
                            }
                            items[c] = null;
                        }
                    }
                }
                else
                {
                    if (items[c])
                    {
                        if (items[c].destroy)
                        {
                            items[c].destroy();
                        }
                        items[c] = null;
                    }
                }

                return tailcount;
            }
        }

        return 0;
    };

    // [component.layout.items:getcount]            // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItemHeadCount = function () { return   this._use_headitem > 0 ?  (this._head_count ?? 0)  :0;   };
    _pComplexComponent._getItemTailCount = function () { return   this._use_tailitem > 0 ?  (this._tail_count ?? 0)  :0;   };
    _pComplexComponent._getItemBodyCount = function () { return /*this._use_bodyitem > 0 ?*/(this._body_count ?? 1)/*:0*/; };
    _pComplexComponent._getItemNullCount = function () { return   this._use_nullitem > 0 ?  (this._null_count ?? 0)  :0;   };
    _pComplexComponent._getItemTempCount = function () { return   this._use_tempitem > 0 ?  (this._temp_count ?? 0)  :0;   };

    // [component.layout.items:getrawcount]         // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItemsRawCount = function (count, head, tail, nill, temp)
    {
        // 이 count는 모든 head/body/tail 모든 row이 sub item 도 포함한 item array의 count
        // 이 count는 bindcount와 매치되는 itemindex이 count가 아님
        count = (((count && count > 0) ? count : this._getBindCount()) * this._getItemBodyCount());

        head = (head !== false ? this._getItemHeadCount() : 0);
        tail = (tail !== false ? this._getItemTailCount() : 0);
        nill = (nill === true  ? this._getItemNullCount() : 0)
        temp = (temp === true  ? this._getItemTempCount() : 0);

        return count + head + tail + nill + temp;
    };

    _pComplexComponent._getPanelSlotIndex = function (itemindex)
    {
        return this._panel ? this._panel._getPanelSlotIndex(itemindex) : ((itemindex ?? 0) + (this._head_count ? 1 : 0));
    };

    // TODO: Items Paging/Scrolling 처리

    // [component.layout.items:getcount]            // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._getItemCount = function (head, tail, nill, temp)
    {
        // 이 count는 기본적으로 bindcount와 연계되는 itemindex의 Count
        // 이 count는 head, tail, null, temp는 명기하기 전에는 제외됨
        // 이 count는 head, tail, null, temp가 있는경우 1개로 처리되어 추가됨
        // 이 count의 fullcount는 item array count 및 slot count와 매치됨
        if (this._is_databind)
            return this._getBindCount()
                + ((head && this._getItemHeadCount()) ? 1 : 0)
                + ((tail && this._getItemTailCount()) ? 1 : 0)
                + ((nill && this._getItemNullCount()) ? 1 : 0)
                + ((temp && this._getItemTempCount()) ? 1 : 0);
        else
            return this._onGetItemCount(head, tail, nill, temp);
    };

    // [component.layout.items:getcount]            // 필요시 override
    _pComplexComponent._onGetItemCount = function (head, tail, nill, temp)
    {
        return (this._onGetItemListCount())
            + ((head && this._onGetItemHeadCount()) ? 1 : 0)
            + ((tail && this._onGetItemTailCount()) ? 1 : 0)
            + ((nill && this._onGetItemNullCount()) ? 1 : 0)
            + ((temp && this._onGetItemTempCount()) ? 1 : 0);
    };
    // [component.layout.items:getcount]            // 필요시 override
    _pComplexComponent._onGetItemHeadCount = function () { return this.headcount ?? 0; };
    _pComplexComponent._onGetItemTailCount = function () { return this.tailcount ?? 0; };
    _pComplexComponent._onGetItemBodyCount = function () { return this.bodycount ?? 1; };
    _pComplexComponent._onGetItemNullCount = function () { return this.nullcount ?? 0; };
    _pComplexComponent._onGetItemTempCount = function () { return this.tempcount ?? 0; };
    _pComplexComponent._onGetItemListCount = function () { return this.itemcount ?? 0; };

    // [component.layout.items:getareawidth]        // 필요시 override     
    _pComplexComponent._onGetItemsAreaWidth = function ()
    {
        return Math.max(this._getClientWidth(), 0);
    };

    // [component.layout.items:getareaheight]       // 필요시 override
    _pComplexComponent._onGetItemsAreaHeight = function ()
    {
        return Math.max(this._getClientHeight(), 0);
    };

