    // [component.layout.items:create]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._createItems = function ()
    {
        if (this._is_items && this._items)
        {
            if (this._is_databind)
            {
                this._createBindItems();
            }
            else
            {
                this._createRepeatItems();
            }
        }
    };
    // [component.layout.items:created]             // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._createdItems = function (window)
    {
        if (this._is_items && this._items)
        {
            // created items
            this.onCreatedItems(window);
        }
    };
    // [component.layout.items.part:createlist]     // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._createPartItemList = function (count)
    {
        if (this._is_items && this._items)
        {
            // create item full list array
            this._items.length = this._getItemsRawCount(count);
        }
    };
    _pComplexComponent._createPartItem = function (bindindex)
    {
        //  if (this._is_items && this._items)
        {
            // get bind/context data
            var bind = this._getBindData(bindindex);
            var ctxt = this._getCtxtData(bindindex, bind);

            // item create
            var item = this.onCreateItem(ctxt, bind, bindindex);

            // get created item
            // var item = this._getBindItem(i);

            if (item)
            {
                // set context itemindex
                this._setItemIndex(item, bindindex);
                // set context iteminfo, bandid
                this._setCtxtItemInfo(item, ctxt, bindindex);
                // set binditeminfo
                this._setBindItemInfo(item, bind, bindindex);
                // set sublayout
                this._setItemSubLayoutInfo(item, bind, bindindex);

                // created
                this._createdItem(item, this._getWindow());

                // set z-index
                this._setItemZIndex(item, 0);

                // set indentsize
                this._setItemIndentSize(item, this._onGetIndentSize());
            }
        }
    };

    // [component.layout.items:created]             // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._createdItem = function (item, window)
    {
        // created items
        if (item)
        {
            if (nexacro._isArray(item))
            {
                for (var i = 0, l = item.length; i < l; i++)
                {
                    var itm = item[i];
                    if (itm)
                        itm.onCreated(window);
                }
            }
            else
            {
                item.onCreated(window);
            }
        }
    };
    // [component.layout.items:update]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._updateItems = function (resetlayout, info)
    {
        this._updateItemsbyBindIndex(0, -1, info);

        this._recalcLayout(resetlayout);
    };
    // [component.layout.items:update]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._updateItemsbyBindIndex = function (bindindex, count, info)
    {
        if (this._is_items && this._items)
        {
            if (bindindex >= 0)
            {
                // loop var
                var i, j;

                // loop cnt
                var n, m;

                for (i = bindindex, n = (count < 0) ? this._getBindCount() : (bindindex + (count ?? 1)); i < n; i++)
                {
                    var item = this._getItem(this._getItemIndexbyBindIndex(i)); if (!item) continue;
                    var bind = this._getBindData(i);

                    if (item)
                    {
                        this._setBindItemInfo(item, bind, i);

                        if (nexacro._isArray(item))
                        {
                            for (j = 0, m = item.length; j < m; j++)
                            {
                                var band = item[j];
                                if (band && band.onUpdateItem)
                                {
                                    band.onUpdateItem(i, info);
                                }
                            }
                        }
                        else
                        {
                            if (item && item.onUpdateItem)
                            {
                                item.onUpdateItem(i, info);
                            }
                        }
                    }
                }
            }
        }

        // TODO : AutoSize Recalc
        /*
        if (relayout)
            this._recalcLayout(false);
        */
    };
    // [component.layout.items:update]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._updateItem = function (item, itemindex, info, bandseq)
    {
        if (item)
        {
            // 확인 : update시 expr값 외에 bind값도 갱신여부
            var bindidx = this._getItemBindIndex(item);
            var bindinfo = this._getBindData(bindidx, nexacro._BindConst.BINDEXPR_DATABINDEXPR, item);

            this._setBindItemInfo(item, bindinfo, bindidx, bandseq);

            if (nexacro._isArray(item))
            {
                for (var i = 0; i < item.length; i++)
                {
                    var band = item[i];
                    if (band)
                    {
                        if (band._resetStatus)
                            band._resetStatus();

                        if (band.onUpdateItem)
                            band.onUpdateItem(bindidx, info);
                    }
                }
            }
            else
            {
                if (item)
                {
                    if (item._resetStatus)
                        item._resetStatus();

                    if (item.onUpdateItem)
                        item.onUpdateItem(bindidx, info);
                }
            }
        }
    };

