    _pComplexComponent._getItemTop    = function (itemindex, stat)  { return this._onGetItemTop(   itemindex, stat ? stat : this._getPanelDefSlotStat()); };
    _pComplexComponent._getItemWidth  = function (itemindex, stat)  { return this._onGetItemWidth( itemindex, stat ? stat : this._getPanelDefSlotStat()); };
