    // [component.layout.items.body:create]     // 필요시 Override
    _pComplexComponent.onCreateItem = function (ctxtdata, binddata, bindindex, nc)
    {
        // loop var
        var i, n;
        var item;

        if (this._is_format_layout && ctxtdata)
        {
            // default item create logic by ctxt

            // create ctxt item control
            item = this.createItemCtxtControl(ctxtdata, binddata, bindindex, nc);
            if (item)
            {
                // default event handler 
                this._setItemEventHandler(item, "onclick", this.on_notify_item_onclick, this);
            }

            return item;
        }
        else
        {
            // default item create logic

            // create item control
            item = this.createItemControl(new nexacro.Button("item", 0, 0, 0, 0, null, null, null, null, null, null, this), bindindex);
            if (item)
            {
                // attach prop
                item.set_text("text");

                // attach event
                this._setItemEventHandler(item, "onclick", this.on_notify_item_onclick, this);
            }

            return item;
        }
    };
