    // [component.layout.formats:get]               // override 제외
    _pComplexComponent._getFormats  = function () { return this._formats; };

    // [component.layout.formats.prop:get]          // fullbind시 override
    _pComplexComponent._onGetFormatsProp   = function () { return "formats"; };
    _pComplexComponent._onGetFormatIdProp  = function () { return "formatid"; };
    _pComplexComponent._onGetFormatExProps = function ()
    {
        return []; // return ["userbandid", "userbandcontroltype", "userbandformats"];
    };

    // [component.layout.formats:set]               // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._setFormats = function (formats)
    {
        // check interface
        if (this._is_format_layout && this._formats)
        {
            if (formats)
            {
                // [component.layout.formats:parse]
                this._parseFormats(formats);
            }
            else
            {
                // [component.layout.formats:clear]
                this._clearFormats();
            }
        }
    };

    // [component.layout.formats:create]            // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._createFormats = function ()
    {
        // check interface
        if (this._is_format_layout && this._formats)
        {
            // create formats
            this._onCreateFormats();
            // set current format
            this._onChangeFormat(this[this._onGetFormatIdProp()]);
        }
        else
        {
            // set no format ctxt info
            this._onCreateNoFormatCtxtInfo();
        }
    };
    // [component.layout.formats:created]           // format create의 created 처리, TODO : MLM Create Flow 정리후 삭제할것
    _pComplexComponent._createdFormats = function ()
    {
        return this._onCreatedFormats();
    };
    // [component.layout.formats:clear]             // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._clearFormats = function ()
    {
        // check interface
        if (this._is_format_layout && this._formats)
        {
            // clear formats
            this._onClearFormats();
            // set empty format
            this._onChangeFormat("");
        }
        else
        {
            // clear formats
            this._onClearFormats();
            // clear no format ctxt info
            this._clearCtxtBaseInfo();
        }
    };
    // [component.layout.formats:update]            // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._updateFormats = function ()
    {
        this._clearFormats();
        this._createFormats();
    };

    // [component.layout.formats:custom]            // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._setUserFormat = function (usrformatinfo, usrformatstr)
    {
        return this._onSetUserFormat(usrformatinfo, usrformatstr);
    };
    // [component.layout.formats:custom]            // UserFormat Interface는 컴포넌트별로 다양함으로 컴포넌트별 직접 userformat 처리
    _pComplexComponent._onSetUserFormat = function (usrformatinfo, usrformatstr)
    {
        /*                                          
        if (this._formats)
        {
            if (usrformatinfo)
            {
                this._formats._setUsrBandNames(usrformatinfo.usrbandnames);   
                this._formats._setUsrControlTypes(usrformatinfo.usrctrltypes);
            }
            if (usrformatstr)
            {
                this._formats._setUsrFormatString(usrformatstr);
            }

            // TODO : Clear
        }
        */
    };

    // [component.layout.formats:parse]            // override는 가급적 최소화
    _pComplexComponent._parseFormats = function (formats)
    {
        // clear formats info
        this._onClearFormats();

        // parse formats info
        this._onParseFormats(formats);
    };
    // [component.layout.formats.formatid:change]   // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._changeFormatId = function (id)
    {
        // check interface
        if (this._is_format_layout && this._formats)
        {
            // change current format
            this._onChangeFormat(id);
        }
    };
    // [component.layout.formats.formatid:clear]    // override는 basic component내에서만 가급적 최소화
    _pComplexComponent._clearFormatId = function (id)
    {
    };

    // [component.layout.formats:getstring]         // override는 가급적 최소화
    _pComplexComponent._onGetStrFormats = function ()
    {
        // return formats string
        return this._p_formats;
    };
    // [component.layout.formats:create]            // override는 가급적 최소화
    _pComplexComponent._onCreateFormats = function ()
    {
        // parse formats string
        if (this._formats && !this._formats._format_parsed)
        {
            this._parseFormats(this._onGetStrFormats() ?? this._formats._getUsrFormatString());
        }
    };
    // [component.layout.formats:created]          // override는 가급적 최소화
    _pComplexComponent._onCreatedFormats = function ()
    {
    };
    // [component.layout.formats:parse]            // override는 가급적 최소화
    _pComplexComponent._onParseFormats = function (formats)
    {
        // change format ref-->own
        if (this._is_formats_ref)
            this._initFormatsLayout(this);

        // parse formats info
        if (this._formats)
            this._formats._parseFormats(formats, this._databind);
    };
    // [component.layout.formats:change]            // override는 가급적 최소화
    _pComplexComponent._onChangeFormat = function (id)
    {
        var formats = this._formats;

        // set current format
        if (formats && formats._format_parsed)
        {
            var applyid = nexacro._nvl(id, this._formats._default_id);

            if (formats._getCurrentID() == applyid)
                return;

            // clear current ctxt
            this._clearCtxtBaseInfo();

            // set current
            formats._setCurrentID(applyid);

            // get current item
            var formatctxt = formats._getCurrentItem();
            if (formatctxt)
            {
                // set context info
                this._setCtxtBaseInfo(formatctxt, formats);
            }

            // [component.bind.bindinfo:apply]
            this._applyBindInfos();

            // [component.bind.value:apply]
            this._applyValue();

            // get current panel
            var panel = this._getPanel();
            if (panel)
            {
                // set panel info
                this._setPanelCtxtInfo(formatctxt, formats);
            }
        }
    };
    // [component.layout.noformats:create]          // override는 가급적 최소화
    _pComplexComponent._onCreateNoFormatCtxtInfo = function ()
    {
        if (this._is_panel_layout && this._panel)
        {
            var panel = this._panel;

            this._null_ctxts = this._use_nullitem ? this._onGetContextDataNull() : null;

            this._head_count = panel._getSlotTargetCount(-1); // Head
            this._body_count = panel._getSlotTargetCount( 0); // Body
            this._tail_count = panel._getSlotTargetCount(-2); // Tail

            if (!this._head_count || this._head_count < 0) this._head_count = 0;
            if (!this._body_count || this._body_count < 0) this._body_count = 0;
            if (!this._tail_count || this._tail_count < 0) this._tail_count = 0;

            this._null_count = this._use_nullitem && nexacro._isArray(this._null_ctxts) ? this._null_ctxts.length : (this._null_ctxts ? 1 : undefined);
        }
        else
        {
            // clear no format ctxt info
            this._onClearCtxtInfo();
        }
    };

    // [component.layout.formats:change]            // override는 가급적 최소화
    _pComplexComponent._onClearFormats = function (id)
    {
        // clear ctxt info
        if (this._ctxtdata)
            this._clearCtxtBaseInfo();

        // clear formats info
        if (this._formats && !this._is_formats_ref)
            this._formats._clear();
    };
    // [component.layout.noformats:clear]           // override는 가급적 최소화
    _pComplexComponent._onClearCtxtInfo = function ()
    {
        this._head_count = 0;
        this._body_count = 0;
        this._tail_count = 0;
        this._null_count = 0;
        this._temp_count = 0;
    };

    // [component.layout.formats:getcoord]          // override는 가급적 최소화
    _pComplexComponent._fetchFormatsCoord = function (bindindex)
    {
        return this._is_format_postyp ? this._fetchFormatsPosition(bindindex) : this._fetchFormatsRowCols(bindindex);
    };
    _pComplexComponent._getFormatsCoord = function (ctxt)
    {
        return this._is_format_postyp ? this._getCtxtFormatsPosition(ctxt) : this._getCtxtFormatsRowCols(ctxt);
    };
    // [component.layout.formats:getrowcol]         // override는 가급적 최소화
    _pComplexComponent._fetchFormatsRowCols = function (bindindex)
    {
        // TODO : Cache 처리할것

        // get context data
        var ctxt = this._getCtxtData(bindindex); if (!ctxt) return [this._getDefCtxtFormatsRowCols()];

        return this._getCtxtFormatsRowCols(ctxt);
    };
    _pComplexComponent._getCtxtFormatsRowCols = function (ctxt)
    {
        var base = this._getCtxtBaseInfo(); if (!base) return [this._getDefCtxtFormatsRowCols()];

        // get index item's position
        if (nexacro._isArray(ctxt))
        {
            var arrs = Array(ctxt.length);

            for (var i = 0, l = ctxt.length; i < l; i++)
            {
                arrs[i] = ctxt[i] ? base._getArrPos(ctxt[i]) : this._getDefCtxtFormatsRowCols();
            }

            return arrs;
        }
        else
        {
            return [ctxt ? base._getArrPos(ctxt) : this._getDefCtxtFormatsRowCols()];
        }
    };
    _pComplexComponent._getDefCtxtFormatsRowCols = function ()
    {
        return [-1, -1, 1, 1];
    };
    // [component.layout.formats:getpos]         // override는 가급적 최소화
    _pComplexComponent._fetchFormatsPosition = function (bindindex)
    {
        // TODO : Cache 처리할것
        // var arrd = [];

        // get context data
        var ctxt = this._getCtxtData(bindindex); if (!ctxt) return [this._getDefCtxtFormatsPosition()];

        return this._getCtxtFormatsPosition(ctxt);
    };
    _pComplexComponent._getCtxtFormatsPosition = function (ctxt)
    {
        var base = this._getCtxtBaseInfo(); if (!base) return [this._getDefCtxtFormatsPosition()];

        // get index item's position
        if (nexacro._isArray(ctxt))
        {
            var arrs = Array(ctxt.length);

            for (var i = 0, l = ctxt.length; i < l; i++)
            {
                arrs[i] = ctxt[i] ? base._getArrPos(ctxt[i]) : this._getDefCtxtFormatsPosition();
            }

            return arrs;
        }
        else
        {
            return [ctxt ? base._getArrPos(ctxt) : this._getDefCtxtFormatsPosition()];
        }
    };
    _pComplexComponent._getDefCtxtFormatsPosition = function ()
    {
        return [0, 0, 0, 0, 0, 0];
    };
    // [component.layout.formats:getcount]         // override는 가급적 최소화
    _pComplexComponent._fetchFormatsCount = function (bindindex)
    {
        // get band format
        var ctxt = this._getCtxtData(bindindex);

        return this._getCtxtFormatsCount(ctxt);
    };
    _pComplexComponent._getCtxtFormatsCount = function (ctxt)
    {
        // get band item's count
        return ctxt ? (nexacro._isArray(ctxt) ? ctxt.length : 1) : (0);
    };
    // [component.layout.formats.context.base:set] 
    _pComplexComponent._setCtxtBaseInfo = function (ctxtinfo, formats, ref)
    {
        // 확인 : 자체 format/상위 format, 자체 databind/상위 databind을 명시적으로 구별하는 형태로 변경
        // 확인 : 외부지정 flag를 내부에서 임의 변경하는 것 --> 명시적으로 별도 내부 flag로 변경할 것, 제거
        // 확인 : ref 지정시 지정된 값을 사용하도록 변경 --> item 생성시 item별 동일한 루틴 수행 제거

        // check formatlayout
        if (ref)
        {
            this._initFormatsLayoutRef(formats);    // ref format 지정
        }

        // check formattype
        var formattype = formats._format_type;
        if (formattype)
        {
            // TODO : 1개 설정으로 Ref 처리
            this._is_format_chkgrp = formattype & nexacro._FormatsConst.FORMATTYPE_MULTIGROUP ? true : false;
            this._is_format_chklvl = formattype & nexacro._FormatsConst.FORMATTYPE_MULTILEVEL ? true : false;
            this._is_format_postyp = formattype & nexacro._FormatsConst.FORMATTYPE_POSITION   ? true : false;
        }

        // clear ctxt
        this._clearCtxtBaseInfo();

        // set context info & cache
        if (ctxtinfo)
        {
            this._ctxtdata = ctxtinfo;

            if (ref)
            {
                    // TODO : 1개 설정으로 Ref 처리
            /*  if (this._use_bodyitem) */  this._body_ctxts = ref._body_ctxts, this._body_count = ref._body_count;
                if (this._use_headitem)     this._head_ctxts = ref._head_ctxts, this._head_count = ref._head_count;
                if (this._use_tailitem)     this._tail_ctxts = ref._tail_ctxts, this._head_count = ref._head_count;
                if (this._use_markitem)     this._mark_ctxts = ref._mark_ctxts, this._head_count = ref._head_count;
                if (this._use_nullitem)     this._null_ctxts = ref._null_ctxts, this._head_count = ref._head_count;
                if (this._use_tempitem)     this._temp_ctxts = ref._temp_ctxts, this._head_count = ref._head_count;
            }
            else
            {
                    // TODO : 미사용 변수는 셋팅제외, 삭제처리
            /*  if (this._use_bodyitem) */  this._body_ctxts = this._onGetContextDataBand(this._formats._body_bands, this._is_format_chklvl),   this._body_count = /*this._use_bodyitem &&*/this._body_ctxts ? (nexacro._isArray(this._body_ctxts) ? this._body_ctxts.length : (this._body_ctxts._values ? this._body_ctxts._values.length : 1)) : 0;
                if (this._use_headitem)     this._head_ctxts = this._onGetContextDataBand(this._formats._head_bands, this._is_format_chklvl),   this._head_count =   this._use_headitem &&  this._head_ctxts ? (nexacro._isArray(this._head_ctxts) ? this._head_ctxts.length : (this._head_ctxts._values ? this._head_ctxts._values.length : 1)) : 0;
                if (this._use_tailitem)     this._tail_ctxts = this._onGetContextDataBand(this._formats._tail_bands, this._is_format_chklvl),   this._tail_count =   this._use_tailitem &&  this._tail_ctxts ? (nexacro._isArray(this._tail_ctxts) ? this._tail_ctxts.length : (this._tail_ctxts._values ? this._tail_ctxts._values.length : 1)) : 0;
                if (this._use_markitem)     this._mark_ctxts = this._onGetContextDataBand(this._formats._mark_bands),                           this._mark_count =   this._use_markitem &&  this._mark_ctxts ? (nexacro._isArray(this._mark_ctxts) ? this._mark_ctxts.length : (this._mark_ctxts._values ? this._mark_ctxts._values.length : 1)) : 0;
                if (this._use_nullitem)     this._null_ctxts = this._onGetContextDataBand(this._formats._null_bands),                           this._null_count =   this._use_nullitem &&  this._null_ctxts ? (nexacro._isArray(this._null_ctxts) ? this._null_ctxts.length : (this._null_ctxts._values ? this._null_ctxts._values.length : 1)) : 0;
                if (this._use_tempitem)     this._temp_ctxts = this._onGetContextDataBand(this._formats._temp_bands),                           this._temp_count =   this._use_tempitem &&  this._temp_ctxts ? (nexacro._isArray(this._temp_ctxts) ? this._temp_ctxts.length : (this._temp_ctxts._values ? this._temp_ctxts._values.length : 1)) : 0;
            }
        }

        // override
        this._onSetCtxtBaseInfo();
    };
    // [component.layout.formats.context.base:clear] 
    _pComplexComponent._clearCtxtBaseInfo = function ()
    {
        // override
        this._onClearCtxtBaseInfo();

        if (this._body_ctxts) this._body_ctxts = null;
        if (this._head_ctxts) this._head_ctxts = null;
        if (this._tail_ctxts) this._tail_ctxts = null;
        if (this._mark_ctxts) this._mark_ctxts = null;
        if (this._null_ctxts) this._null_ctxts = null;

        if (this._body_count) this._body_count = 0;
        if (this._head_count) this._head_count = 0;
        if (this._tail_count) this._tail_count = 0;
        if (this._mark_count) this._mark_count = 0;
        if (this._null_count) this._null_count = 0;

        // clear ctxt
        if (this._ctxtdata) this._ctxtdata = null;
    };
    // [component.layout.formats.context.base:get] 
    _pComplexComponent._getCtxtBaseInfo = function ()
    {
        // get context info
        return this._ctxtdata;
    };


    // [component.layout.formats.context:get] 
    _pComplexComponent._getCtxtData = function (bindindex, bind, beginfinal)
    {
        if (bindindex === undefined) // default
        {
            return this._onGetContextData();
        }

        switch (bindindex)
        {
            default:
            case  0: return this._onGetContextDataBody(bindindex, bind, beginfinal);
            case -1: return this._onGetContextDataHead(bindindex, bind, beginfinal);
            case -2: return this._onGetContextDataTail(bindindex, bind, beginfinal);
            case -3: return this._onGetContextDataMark(bindindex, bind);
            case -4: return this._onGetContextDataNull(bindindex, bind);
            case -5: return this._onGetContextDataTemp(bindindex, bind);
        }
    };

    // [component.layout.formats.context:set]
    _pComplexComponent._setCtxtInitInfo = function (item, ctxtdata, binddata, bindindex)
    {
        // set item by info
        if (item && ctxtdata)
        {
            var ctxt = nexacro._isArray(ctxtdata) ? ctxtdata[0] : ctxtdata;     // ctxt array --> exception
            var cset = ctxt._setts;                                             // always _setts format parse attrb list

            // cache ctxt id,seq
            if (item._setItemCtxtId)
            {
                item._setItemCtxtId(item, ctxt._id);
            }
            if (item._setItemSubIndex)
            {
                item._setItemSubIndex(item, ctxt._seq);
            }

            // cache coords
            if (item._setItemCoords)
            {
                item._setItemCoords(item, this._getFormatsCoord(ctxt));
            }

            // set init props from ctxtinfo
            var initprop = this._ctxtinitprop; // ["childtype"];

            // set post props
            if (cset)
            {
                for (var prop of initprop)
                {
                    var func = cset[prop]; if (!func) continue;
                    var data = ctxt[prop];

                    // set prop info
                    if (Array.isArray(data))    func.apply(item, data);
                    else                        func.call(item, data);

                    /*
                    if (item._setChildTypeList && prop == "childtype")
                    {
                        item._setChildTypeList(data);
                    }
                    */
                }
            }

            // set init props from bindinfo
            if (binddata)
            {
                var infos = binddata._getBindInfos();
                var start = binddata._chkBindInfos();

                // TODO : bindinfo를 item에 맞게 최적화, 해당 item 외의 bind array 루프생략
                for (var i = start, n = infos.length; i < n; i++)
                {
                    // check info
                    var info = infos[i]; if (!info || info.target || info.baseid != ctxt._id) continue;

                    // TODO : 비설정값 대상 체크대신 설정대상 항목리스트로 사전 처리후 직접접근으로 변경
                    if (!initprop.includes(info.propid)) continue;

                    var comp = nexacro._nvl(info.target, false) ? this._getBindComp(item, info.target) : item; if (!comp) continue;
                    var func = nexacro._nvl(info.setter, false) ? this._getBindFunc(comp, info.setter) : null; if (!func) continue;

                    data = info.values;

                    // set info
                    if (nexacro._isArray(data)) func.apply(comp, data);
                    else                        func.call(comp, data);

                    /*
                    if (item._setChildTypeList && prop == "childtype")
                    {
                        item._setChildTypeList(data);
                    }
                    */
                }
            }
        }
    };
    _pComplexComponent._setCtxtItemInfo = function (item, ctxtdata, bindindex, subindex)
    {
        // set item by info
        if (item && ctxtdata)
        {
            var i, n, m;

            if (nexacro._isArray(item))
            {
                if (nexacro._isArray(ctxtdata))
                {
                    // set array
                    for (i = 0, n = item.length, m = ctxtdata.length; i < n; i++)
                    {
                        this._setCtxtItemInfo(item[i], ctxtdata[i % m], bindindex, i);
                    }
                }
                else
                {
                    // set array
                    for (i = 0, n = item.length; i < n; i++)
                    {
                        this._setCtxtItemInfo(item[i], ctxtdata, bindindex, i);
                    }
                }
            }
            else
            {
                var ctxt = nexacro._isArray(ctxtdata) ? ctxtdata[0] : ctxtdata;     // ctxt array --> exception
                var cset = ctxt._setts;                                             // always _setts format parse attrb list
                var csub = ctxt._items;                                             // always _items format parse child list
                var isub = item._children;                                          // just item's child, deny item's items

                var postprop = this._ctxtpostprop; // ["fittocontents"];

                // set pre props
                if (cset)
                {
                    for (var prop in cset)
                    {
                        // TODO : 비설정값 대상 체크대신 설정대상 항목리스트로 사전 처리
                        if (postprop.includes(prop)) continue;

                        // get prop info
                        var func = cset[prop]; if (!func) continue;
                        var data = ctxt[prop];

                        // set prop info
                        if (Array.isArray(data))    func.apply(item, data);
                        else                        func.call(item, data);
                    }
                }

                // set child
                if (csub && isub)
                {
                    for (i = 0, n = isub.length, m = csub.length; i < n; i++)
                    {
                        this._setCtxtItemInfo(isub[i], csub[i % m], bindindex, i);
                    }
                }

                // set post props
                if (cset)
                {
                    for (var prop of postprop)
                    {
                        var func = cset[prop]; if (!func) continue;
                        var data = ctxt[prop];

                        // set prop info
                        if (Array.isArray(data))    func.apply(item, data);
                        else                        func.call(item, data);

                        if (item._setItemFitSize && prop == "fittocontents")
                        {
                            this._setItemFitSize(item, data);
                        }
                    }
                }
            }
        }
    };

    // [component.layout.ctxt:create]              // override는 basic component내에서만 가급적 최소화
    _pComplexComponent.createCtxtControl = function (ctxt, bind, seq, is_child)
    {
        if (ctxt)
        {
            // TODO : _id 대신 .id 로 수정할것

            // make type & name
            var _name;
            if (is_child)   // 현재 child(cell)는 id로..
            {
                _name = ctxt._id;
            }
            else
            {
                _name = ctxt._id + (seq ?? "");
            }

            var _posa = ctxt._pos ? ctxt._pos : null;
            var _item = null;

            // get type construct
            var _construc = ctxt._construc;

            if (!_construc)
            {
                _construc = ctxt._construc = nexacro._getTypeConstructor(ctxt._typename, "nexacro.ComplexComponent");
            }

            if (_construc)
            {
                // create ctxt control 
                if (_posa)
                {
                    _item = new _construc(_name, _posa[0], _posa[1], _posa[2], _posa[3], _posa[4], _posa[5], null, null, null, null, this);
                }
                else
                {
                    _item = new _construc(_name, 0, 0, 0, 0, null, null, null, null, null, null, this);
                }
            }

            if (_item)
            {
                if (is_child)
                {
                    // set child id list
                    this._addChildCollection(_name, _item);
                }

                if (_item._setCtxtBaseInfo)
                {
                    // set formats context
                    _item._setCtxtBaseInfo(ctxt, this._formats, this);
                }
            //  if (_item._setCtxtInitInfo)
                {
                    // set initial context
                    this._setCtxtInitInfo(_item, ctxt, bind, seq);
                }

                // override for added create logic
                this.onCreateCtxtControl(_item, ctxt, bind, seq);
            }

            return _item;
        }
    };

    // [component.layout.ctxt:createinfo]            // override후 는 basic component내에서만 가급적 최소화
    _pComplexComponent._setAddedCreateInfo = function (comp, ctxt, bind, seq)
    {
        this._onSetAddedCreateInfo(comp, ctxt, bind, seq);
    };


    // [하위 Component 처리]
    // 개별 Component별 Override 처리

