    // [component.layout.formats.context:get] 
    _pComplexComponent._onGetContextData = function ()
    {
        return this._ctxtdata;
    };
    _pComplexComponent._onGetContextDataLevel = function (lvlnames)
    {
        if (lvlnames)
        {
            var ctxt = Object.create(lvlnames);
            var lvls = Object.entries(lvlnames);

            for (let k in ctxt) ctxt[k] = {};

            ctxt._lvlids = new Array(lvls.length);

            for (let l of lvls) ctxt._lvlids[l[1]] = l[0];
        }
        else
        {
            var ctxt = Object.create({ "none": {} });

            ctxt._lvlids = ["none"];
        }

        return ctxt;
    };
    _pComplexComponent._onGetContextDataNormal = function ()
    {
        var ctxt = {};

        return ctxt;
    };
    // 확인 : index-->chklvl로 수정됨, ListView 확인하여 제거
    _pComplexComponent._onGetContextDataBand = function (bands, chklvl)
    {
        if (this._ctxtdata && this._ctxtdata._getBand && bands && bands.length)
        {
            if (chklvl === true)
            {
                let none = nexacro._FormatsConst.FORMATBANDIDX_NONE;
                var ctxt = this._onGetContextDataLevel(this._formats._lvls_names);

                // band in foramts & level
                for (var i = 0, l = bands.length; i < l; i++)
                {
                    var band = this._ctxtdata._getBand(bands[i], false, this._formats);
                    if (band)
                    {
                        ctxt[band.level][band.id] = band;
                    //  ctxt._lvlids[band._ilvl] = band.level;
                    }
                }
                /*  if (ctxt && nexacro._isObject(ctxt)) */
                {
                    for (let ix in ctxt) { ctxt[ix]._values = Object.values(ctxt[ix]); }
                }
                if (!ctxt._lvlids[none])
                {
                    for (let id of ctxt._lvlids) { if (id) { ctxt._lvlids[none] = id; break; } }
                }
            }
            else
            {
                var ctxt = this._onGetContextDataNormal();

                // band in foramts
                for (var i = 0, l = bands.length; i < l; i++)
                {
                    var band = this._ctxtdata._getBand(bands[i], false);
                    if (band)
                    {
                        ctxt[band.id] = band;
                    }
                }

                if (ctxt && nexacro._isObject(ctxt)) ctxt._values = Object.values(ctxt);
            }

            return ctxt;
        }
        return {};
    };

    // [component.layout.formats.context.band:get]
    _pComplexComponent._onGetLevelIdxByBindLevel = function (bindindex, bind)
    {
        var bandnone = nexacro._FormatsConst.FORMATBANDIDX_NONE;

        var bindroot = this._getBindRootLevel(); if (bindroot < 0) return bandnone;
        var bandroot = this._getBandRootLevel(); if (bandroot < 0) return bandnone;

        var bindcurr = parseInt(bind ? bind._getLevelValue() : this._bringLevelBindValue(bindindex)); if (isNaN(bindcurr)) return bandnone;

        if (bindcurr <= bindroot && (!this._isPopupContains() || this._isPopupOverflow())) return bandroot;

        var bindleaf = this._getBindLeafLevel(); if (bindleaf < 0) return bandnone;
        var bandleaf = this._getBandLeafLevel(); if (bandleaf < 0) return bandnone;

        if (bindcurr >= bindleaf) return bandleaf;

        var bandbrch = this._getBandBrchLevel(); if (bandbrch < 0) return bandnone;

        return bandbrch;
    };
    _pComplexComponent._onGetCtxtLevelIX = function (bindindex, bind, beginfinal)
    {
        return bindindex < 0 ? this._onGetLevelIdxByLayoutLevel(bindindex) : this._onGetLevelIdxByBindLevel(bindindex, bind);
    };
    _pComplexComponent._onGetCtxtLevelID = function (ctxts, lvlidx)
    {
        return lvlidx < ctxts._lvlids.length && ctxts[ctxts._lvlids[lvlidx]]._values.length ? ctxts._lvlids[lvlidx] : ctxts._lvlids[0];
    };
    _pComplexComponent._onGetBindGroupID = function (bindindex, bind, l)
    {
        var v = bind ? bind._getGroupValue() : bindindex >= 0 ? this._bringGroupBindValue(bindindex) : null;

        return v ? this._onGetBindTypeName(v, l) : null;
    };
    _pComplexComponent._onGetBindTypeName = function (v, l)
    {
        return v;
    };
    _pComplexComponent._onGetCtxtGroupID = function (ctxts, bindindex, bind, beginfinal, lvlidx)
    {
        if (ctxts)
        {
            var bandnms = this._onGetBindGroupID(bindindex, bind, lvlidx);

            if (bandnms)
            {
                if (ctxts[bandnms]) return bandnms;
            }

            if (bindindex < 0)
            {
                bandnms = this._formats._getUsrDefBandNames(bindindex) ??
                          this._formats._getOrgDefBandNames(bindindex) ??
                          this._formats._getBandNames(bindindex);

                if (bandnms)
                {
                    var bandnm = nexacro._isArray(bandnms) ? bandnms[lvlidx ?? 0] : bandnms;

                    if (ctxts[bandnm]) return bandnm;
                }
            }
            {
                bandnms = this._formats._getUsrDefBandNames(beginfinal) ??
                          this._formats._getOrgDefBandNames(beginfinal) ??
                          this._formats._getBandNames(beginfinal);

                if (bandnms)
                {
                    var bandnm = nexacro._isArray(bandnms) ? bandnms[lvlidx ?? 0] : bandnms;

                    if (ctxts[bandnm]) return bandnm;
                }
            }

            var val = ctxts._values;

            if (val.length && val[0])
            {
                return val[0].id;
            }
        }

        bandnms = this._formats._default_band;

        return (nexacro._isArray(bandnms)) ? bandnms[0] : bandnms;
    };

    _pComplexComponent._onGetContextDataCtxt = function (ctxt, bindindex, bind, beginfinal)
    {
        if (this._is_format_layout && this._formats && bindindex !== undefined && ctxt)
        {
            var lidx, ltxt, rtxt, clid, cgid;

            if (this._is_format_chklvl)
            {
                if (ctxt)
                {
                    lidx = this._onGetCtxtLevelIX(bindindex, bind, beginfinal);
                    clid = this._onGetCtxtLevelID(ctxt, lidx)
                    ltxt = ctxt[clid];
                }

                if (ltxt)
                {
                    if (this._is_format_chkgrp)
                    {
                        cgid = this._onGetCtxtGroupID(ltxt, bindindex, bind, beginfinal, lidx);
                        rtxt = ltxt[cgid];
                    }
                    else
                    {
                        rtxt = ltxt._values;
                    }
                }
            }
            else
            {
                ltxt = ctxt;

                if (ltxt)
                {
                    if (this._is_format_chkgrp)
                    {
                        cgid = this._onGetCtxtGroupID(ltxt, bindindex, bind, beginfinal);
                        rtxt = ltxt[cgid];
                    }
                    else
                    {
                        rtxt = ltxt._values;
                    }
                }
            }

            if (rtxt) 
            {
                if (nexacro._isArray(rtxt))
                {
                    if (rtxt.length == 1) return rtxt[0];
                    if (rtxt.length == 0) return null;
                }

                return rtxt;
            }
        }

        // null 리턴은 format 구성이 불완전 구성이라는 것
        // 불완전 format 에서 정확하게 표시되지 않음
        // 완전한 format 을 구성해 사용하는 것이 기본임

        return null;
    };

    // [component.layout.formats.context:getband]   // Override 없음
    _pComplexComponent._onGetContextDataBody = function (bindindex, bind, bgnf) { return this._onGetContextDataCtxt(this._body_ctxts, bindindex, bind, bgnf); };
    _pComplexComponent._onGetContextDataHead = function (bindindex, bind, bgnf) { return this._onGetContextDataCtxt(this._head_ctxts, bindindex, bind, bgnf); };
    _pComplexComponent._onGetContextDataTail = function (bindindex, bind, bgnf) { return this._onGetContextDataCtxt(this._tail_ctxts, bindindex, bind, bgnf); };

    // [component.layout.formats.context:getband]   // Override 없음
    _pComplexComponent._onGetContextDataMark = function (bindindex, bind) { return this._formats && this._mark_ctxts ? this._mark_ctxts._values : null; };
    _pComplexComponent._onGetContextDataNull = function (bindindex, bind) { return this._formats && this._null_ctxts ? this._null_ctxts._values : null; };
    _pComplexComponent._onGetContextDataTemp = function (bindindex, bind) { return this._formats && this._temp_ctxts ? this._temp_ctxts._values : null; };

    // [component.layout.formats.context:getbandcustom]     // 컴포넌트별 override
    _pComplexComponent._onGetCustomCtxtMarkBand = function (band, format, ctxt) { return ctxt; };
    _pComplexComponent._onGetCustomCtxtNullBand = function (band, format, ctxt) { return ctxt; };
    _pComplexComponent._onGetCustomCtxtTempBand = function (band, format, ctxt) { return ctxt; };

    // [component.layout.formats.context:getctrlcustom]     // 컴포넌트별 override
    _pComplexComponent._onGetCustomCtxtMarkCtrl = function (ctrl, format, ctxt) { return ctxt; };
    _pComplexComponent._onGetCustomCtxtNullCtrl = function (ctrl, format, ctxt) { return ctxt; };
    _pComplexComponent._onGetCustomCtxtTempCtrl = function (ctrl, format, ctxt) { return ctxt; };

    // [component.layout.formats.context:getheadtailshow]   // 컴포넌트별 override
    _pComplexComponent._onGetContextShowType = function ()
    {
        return [[false, true, false]];  // [[showhead,showbody,showtail],...]
    }

    // [component.layout.formats.context:getsize]   // Override 없음
    _pComplexComponent._getContextSize = function (parentwidth, parentheight, originwidth, originheight)
    {
        return this._ctxtdata ? [this._onGetContextWidth(parentwidth, originwidth), this._onGetContextHeight(parentheight, originheight)] : [10, 5];
    };
    // [component.layout.formats.context:getsize]   // Override 없음
    _pComplexComponent._getContextWidth = function (parentwidth, originwidth) { return this._onGetContextWidth(parentwidth, originwidth); }
    _pComplexComponent._getContextHeight = function (parentheight, originheight) { return this._onGetContextHeight(parentheight, originheight); }

    // [component.layout.formats.context:getsize]   // 필요시 Override
    _pComplexComponent._onGetContextWidth = function (parentwidth, originwidth)
    {
        if (this._ctxtdata && this._ctxtdata.__ap)
        {
            var a = this._ctxtdata.__ap;
            var c = parentwidth ?? originwidth ?? (this.parent ? this.parent._getClientWidth() : this._getClientWidth());

            var l = this._convCValueFloor(a[0], c);
            var w = this._convCValueFloor(a[2], c);
            var r = this._convCValueFloor(a[4], c);

            if (w === undefined)
            {
                if (l !== undefined && r != undefined)
                    w = c - r - l;
            }

            return w;
        }

        return 10; // popup error size : 10 width
    };
    // [component.layout.formats.context:getsize]   // 필요시 Override
    _pComplexComponent._onGetContextHeight = function (parentheight, originheight)
    {
        if (this._ctxtdata && this._ctxtdata.__ap)
        {
            var a = this._ctxtdata.__ap;
            var c = parentheight ?? originheight ?? (this.parent ? this.parent._getClientHeight() : this._getClientHeight());

            var t = this._convCValueFloor(a[1], c);
            var h = this._convCValueFloor(a[3], c);
            var b = this._convCValueFloor(a[5], c);

            if (h === undefined)
            {
                if (t !== undefined && b != undefined)
                    h = c - b - t;
            }

            return h;
        }

        return 5; // popup error size : 5 height
    };


