    // [component.bind.databind.data:set]
    _pComplexComponent._setBindData = function (bindindex, bindinfo, data)
    {
        if (this._databind)
            return this._databind._setBindData(bindindex, bindinfo, data);
    };
    _pComplexComponent._setBindColumn = function (bindindex, col, data)
    {
        if (this._databind)
            return this._databind._setBindColumn(bindindex, col, data);
    };
    _pComplexComponent._setBindColumnByID = function (bindindex, colid, data)
    {
        if (this._databind)
            return this._databind._setBindColumnByID(bindindex, colid, data);
    };

    // [component.bind.databind.data:update]
    _pComplexComponent._appendBindRow = function (bindindex, rowitem)
    {
        if (this._databind)
            return this._databind._appendBindRow(bindindex, rowitem);
    };
    _pComplexComponent._insertBindRow = function (bindindex, rowitem)
    {
        if (this._databind)
            return this._databind._insertBindRow(bindindex, rowitem);
    };
    _pComplexComponent._subsetBindRow = function (bindindex, rowitem, addlast)
    {
        if (this._databind)
            return addlast ?
                this._databind._subaddBindRow(bindindex, rowitem) :
                this._databind._subinsBindRow(bindindex, rowitem);
    };
    _pComplexComponent._deleteBindRow = function (bindindex)
    {
        if (this._databind)
            return this._databind._deleteBindRow(bindindex);
    };
    _pComplexComponent._moveBindRow = function (bindindex, tarindex)
    {
        if (this._databind)
            return this._databind._moveBindRow(bindindex, tarindex);
    };
    _pComplexComponent._exchangeBindRow = function (bindindex, tarindex)
    {
        if (this._databind)
            return this._databind._exchangeBindRow(bindindex, tarindex);
    };
    _pComplexComponent._searchBindRow = function (colid, value)
    {
        if (this._databind)
            return this._databind._searchBindRow(this._databind._getBindColIndex(colid), value);
    };

    // [component.bind.databind.target:get]
    _pComplexComponent._getBindBase = function (item, basesq)
    {
        return basesq >= 0 ? item[basesq] : null;
    };
    _pComplexComponent._getBindFunc = function (comp, setter)
    {
        return comp[setter];
    };
    _pComplexComponent._getBindComp = function (base, target)
    {
        //  if (!base && !target) return;

        if (nexacro._isArray(target))
        {
            var basis = base;

            for (var i = 0, l = target.length; i < l && basis; i++)
            {
                basis = basis._findChild ? basis._findChild(target[i]) : basis[target[i]];
            }

            return basis;
        }
        else
        {
            return base._findChild ? base._findChild(target) : base[target];
        }
    };

    // [component.bind.databind.item:setinfo]
    _pComplexComponent._setBindItemInfo = function (item, binddata, bindindex, bandseq)
    {
        // set item by info
        if (item && binddata)
        {
            var i, n;

            var infos = binddata._getBindInfos();
            var start = binddata._chkBindInfos();

            var info, base, comp, func, data;

            if (nexacro._isArray(item))
            {
                for (i = start, n = infos.length; i < n; i++)
                {
                    // check info
                    info = infos[i]; if (!info) continue;

                    base = nexacro._nvl(info.baseid, false) ? this._getBindBase(item, info.basesq) : null; if (!base) continue;
                    comp = nexacro._nvl(info.target, false) ? this._getBindComp(base, info.target) : base; if (!comp) continue;
                    func = nexacro._nvl(info.setter, false) ? this._getBindFunc(comp, info.setter) : null; if (!func) continue;

                    data = info.values;

                    // set info
                    if (nexacro._isArray(data)) func.apply(comp, data);
                    else                        func.call(comp, data);
                }
            }
            else if (bandseq != undefined)
            {
                for (i = start, n = infos.length; i < n; i++)
                {
                    // check info
                    info = infos[i]; if (!info || info.basesq != bandseq) continue;

                    comp = nexacro._nvl(info.target, false) ? this._getBindComp(item, info.target) : item; if (!comp) continue;
                    func = nexacro._nvl(info.setter, false) ? this._getBindFunc(comp, info.setter) : null; if (!func) continue;

                    data = info.values;

                    // set info
                    if (nexacro._isArray(data)) func.apply(comp, data);
                    else                        func.call(comp, data);
                }
            }
            else
            {
                for (i = start, n = infos.length; i < n; i++)
                {
                    // check info
                    info = infos[i]; if (!info || info.baseid != item.id) continue;

                    comp = nexacro._nvl(info.target, false) ? this._getBindComp(item, info.target) : item; if (!comp) continue;
                    func = nexacro._nvl(info.setter, false) ? this._getBindFunc(comp, info.setter) : null; if (!func) continue;

                    data = info.values;

                    // set info
                    if (nexacro._isArray(data)) func.apply(comp, data);
                    else                        func.call(comp, data);
                }
            }
        }
    };

    // [component.bind.valuebind:init]              // value property가 없거나 다른 property로 처리시 override
    _pComplexComponent._onGetBindableProperties = function ()      // 왜 Properties 복수지??
    {
        // return value bind property name
        return "value";
    };

    // [component.bind.databind:init]               // innerbind/fullbind시 override
    _pComplexComponent._onGetBindDataProp = function ()
    {
        return this._is_databind ? this._is_xmlbind || this._is_jsonbind ? "binddatasource" : this._is_fullbind ? "binddataset" : "innerdataset" : "";
    };
    // [component.bind.databind:init]               // innerbind/fullbind시 override
    _pComplexComponent._onGetBindDataSource = function ()
    {
        // return dataset string property
        if (this._is_fullbind) return this._p_binddataset  ? this._p_binddataset  : this._p_binddatasource;
        if (this._is_databind) return this._p_innerdataset ? this._p_innerdataset : this._p_binddatasource;
        return null;
    };
    // [component.bind.databind:init]               // innerbind/fullbind시 override
    _pComplexComponent._onGetBindDataKey = function ()
    {
        // return datactxt key string
        return "*";
    };

    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetCodeColumn = function ()
    {
        return this.codecolumn ? this.codecolumn : "#rowindex";
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetLevelColumn = function ()
    {
        return this.levelcolumn ? this.levelcolumn : "#rowlevel";
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetGroupColumn = function ()
    {
        return this.groupcolumn ? this.groupcolumn : "#rowgroup";
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetDataColumns = function ()
    {
        return [this.datacolumn ? this.datacolumn : "#nodename"];
    };
    // [component.bind.databind:init]               // innerbind/fullbind시 override
    _pComplexComponent._onGetCodeProp = function ()
    {
        return this._is_fullbind ? "#rowindex" : "codecolumn";
    };
    // [component.bind.databind:init]               // innerbind/fullbind시 override
    _pComplexComponent._onGetLevelProp = function ()
    {
        return this._is_fullbind ? "#rowlevel" : "levelcolumn";
    };
    // [component.bind.databind:init]               // innerbind/fullbind시 override
    _pComplexComponent._onGetGroupProp = function ()
    {
        return this._is_fullbind ? "#rowgroup" : "groupcolumn";
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetDataProps = function ()
    {
        return ["datacolumn"];
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetBindProps = function ()
    {
        return []; // ["startindex", "finalindex", "minlevel", "maxlevel", "extlevel"];  // level 속성 값은 별도 처리로 제외
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetCodeBindInfo = function ()
    {
        return this._is_databind && this._is_innerbind ? this.createCodeBindInfo() : null;
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetLevelBindInfo = function ()
    {
        return this._is_databind && this._is_levelbind ? this.createLevelBindInfo() : null;
    };
    // [component.bind.databind:init]               // innerbind시 override
    _pComplexComponent._onGetGroupBindInfo = function ()
    {
        return this._is_databind && this._is_levelbind ? this.createGroupBindInfo() : null;
    };
    // [component.bind.databind:init]               // databind시 override
    _pComplexComponent._onGetDataBindInfos = function ()
    {
        if (this._is_databind)
        {
            if (this._is_fullbind)
                return this._onGetFullBindInfos();

            var bindinfo = this.createDataBindInfo();
            if (bindinfo)
                return [bindinfo];
        }

        return null;
    };
    // [component.bind.databind:init]               // databind시 override
    _pComplexComponent._onGetFullBindInfos = function ()
    {
        // formats fullbind
        if (this._formats)
        {
            var bindinfos = this._formats._getBindInfos();
            if (bindinfos && bindinfos.length)
                return nexacro._clone(bindinfos);
        }

        return null;
    };

    // [component.bind:initbind]                    // Override 최소화
    _pComplexComponent._onInitBindSource = function (columnid, propid, ds)
    {
        if (this._is_created)
        {
            // [component.databind:init]      
            if (this._is_databind) this._resetBindInfo();

            this._clearItems();
        }

        // [component.valuebind:init]                   
        // [component.valueexpr:init]                   
        nexacro.SimpleComponent.prototype._onInitBindSource.call(this);
    };

    // [component.bind.valuebind:change]            // Override 최소화
    _pComplexComponent._onChangeBindSource = function (propid, ds, row, col)
    {
        // [component.databind:change]   
        if (this._is_created)
        {
            // [component.databind:init]      
            if (this._is_databind)
            {
                this._resetBindInfo();
                this._recreateItems();
            }
        }

        // [component.valuebind:changebind]                   
        // [component.valueexpr:changebind]                   
        nexacro.SimpleComponent.prototype._onChangeBindSource.call(this, propid, ds, row, col);
    };

    // [component.bind.event:load]   
    _pComplexComponent._callback_onload = function (obj, e)
    {
        // TODO : REASON Action
        if (this._is_databind && this._is_created)
        {
            this._resetBindInfo();
            this._recreateItems();
        }
    };
    // [component.bind.event:rowsetchanged]   
    _pComplexComponent._callback_onvaluechanged = function (obj, e)
    {
        // TODO : REASON Action
        if (this._is_databind && this._is_created)
        {
            this._updateItemsbyBindIndex(e.row, 1, e);
        }
    };
    // [component.bind.event:columnchanged]   
    _pComplexComponent._callback_oncolumnchanged = function (obj, e)
    {
        // TODO : REASON Action
    };
    // [component.bind.event:rowsetchanged]   
    _pComplexComponent._callback_onrowsetchanged = function (obj, e)
    {
        // TODO : REASON Action
        if (this._is_databind && this._is_created)
        {
            if (this._databind._isDataSetEnableEvent())
            {
            //  this._resetBindInfo();
                this._recreateItems(this._getItemIndexbyBindIndex(obj.rowposition));
            }
        }
    };
    // [component.bind.event:rowposchanged]   
    _pComplexComponent._callback_onrowposchanged = function (obj, e)
    {
        // TODO : REASON Action
        if (this._is_databind && this._is_created)
        {
            var sync = this._onCheckSelectDataSync(); if (!sync) return;
            
            if (this._beginChangeRowPosition()) return;

            var idx = this._getItemIndexbyBindIndex(obj.rowposition, sync>0);

            var sel = this._onGetSelectArgument(idx, -1, -1, true, false);
            this._onSetCurrentSelect(sel);

            if (this._finalChangeRowPosition()) return;
        }
    };

    _pComplexComponent._beginChangeRowPosition = function () { return !(this.__changeRowposition ? false : this.__changeRowposition = true); };
    _pComplexComponent._finalChangeRowPosition = function () { return !(this.__changeRowposition = false); };

    _pComplexComponent._on_rowposition_change = function (bindidx, bandidx, ctrlidx)
    {
        if (this._is_databind && this._is_created && this._onCheckSelectDataSync())
        {
            if (this._beginChangeRowPosition()) return;

            var ret = false;
            var binddata = this._getBindDataSet();
            if (binddata)
            {
                ret = bindidx == binddata._setRowPosition(bindidx, 51);
            }

            if (this._finalChangeRowPosition()) return ret;
        }
    };

