    _pComplexComponent.on_apply_prop_enable = function (v)
    {
        nexacro.SimpleComponent.prototype.on_apply_prop_enable.call(this, v);

        // TODO : NCChildList로 변경
        if (this._is_scrollable == true)
        {
            if (this.vscrollbar) this.vscrollbar._setEnable(v);
            if (this.hscrollbar) this.hscrollbar._setEnable(v);
            if (this.vspinbar) this.vspinbar._setEnable(v);
            if (this.hspinbar) this.hspinbar._setEnable(v);
        }

        if (this._is_expandable == true)
        {
            if (this.expandbar)
                this.expandbar._setEnable(v);
        }
    };

