    //===============================================================
    // nexacro.ComplexComponent : Overflow
    //===============================================================

    // [Complex Component 처리]
    // Overflow는 Scroll/Expand 처리의 기본 설정만 제공
    // Simple에서는 현재 별도 처리 없고 Complex에서 별도 처리

    // [component.overflow:init]                             // 이부분 override는 Complex만
    _pComplexComponent._initOverflow = function ()
    {
        if (this._is_scrollable)
        {
            this._use_native_scroll = true;
            this._use_native_scroll_size = true;

            this._use_translate_scroll = false;
         // this._use_translate_scroll_force = false;
            this._use_translate_move = false;

            this._use_container_move = true;
            this._use_container_multi = false;
        }
    };

    // [component.overflow:get]                             // 필요시 override
    _pComplexComponent._getOverflowType = function ()
    {
        var flag = this._use_partitem ? nexacro._PanelConst.SLOT_OVERFLOWTYPE_PARTSLOT : 0;

        if (this._is_scrollable) return flag | nexacro._PanelConst.SLOT_OVERFLOWTYPE_SCROLL;
        if (this._is_expandable) return flag | nexacro._PanelConst.SLOT_OVERFLOWTYPE_POPUP;
    };
    _pComplexComponent._getOverflowControl = function ()
    {
        if (this._is_expandable) return this.expandbar;
    };

    // [component.overflow:check]                           // 가급적 override 제외
    _pComplexComponent._isOverflowTypeNCScroll = function () { return this._is_scrollable && this._is_nc_scroll && (this._isOverflowTypeScroll() || this._isOverflowTypeSpin() || this._isOverflowTypePaging()); };
    _pComplexComponent._isOverflowTypeNCExpand = function () { return this._is_expandable && this._is_nc_expand && (this._isOverflowTypeExpand()); };

    // [component.overflow:check]                           // 사용시 override 필수
    _pComplexComponent._isOverflowTypeScroll = function () { return this._is_scrollable & true; };
    _pComplexComponent._isOverflowTypeSpin   = function () { return this._is_scrollable & false; };
    _pComplexComponent._isOverflowTypePaging = function () { return this._is_scrollable & false; };
    _pComplexComponent._isOverflowTypeExpand = function () { return this._is_expandable; };
    _pComplexComponent._isOverflowCtrInside  = function () { return false; };
    _pComplexComponent._isOverflowCtrOutside = function () { return true; };


    //===============================================================
    // nexacro.ComplexComponent : Scroll
    //===============================================================

    // [ComplexComponent Component 처리]
    // Scroll의 기본적인 구성은 ComplexComponent 에서 제공
    // 하위 Component에서는 h/v scroll event만 Override

    /*
    _pComplexComponent.dragscrolltype = "all";      // drag/scroll 동시지원시 추가
    */

    // [component.scroll:create]                    // override 없음
    _pComplexComponent._createScroll = function ()
    {
        if (this._is_nc_scroll)
        {
            // create manager
            this._createScrollManager();

            // create control --> Scroll Control 실제 생성은 _resetScroll에서 일괄 동적 처리
            //  this._createScrollControl(); 
        }
    };
    // [component.scroll.manager:create]            // override 없음
    _pComplexComponent._createScrollManager = function ()
    {
        if (this._use_scrollmanager)
        {
            return this._scrollmanager = new nexacro._ScrollManager(this);
        }
    };
    _pComplexComponent._getScrollManager = function ()
    {
        if (this._use_scrollmanager)
        {
            return this._scrollmanager ? this._scrollmanager : this._createScrollManager();
        }
    };
    // [component.scroll.control:create]            // override 없음
    _pComplexComponent._createScrollControl = function ()
    {
        // _resetScroll로 모두 처리

        // 확인 : ctrlset 대응 (우선 SCROLLCTRLSET_SPINBAR 대응, 이후 SCROLLCTRLSET_STEPBAR 대응)
        // 확인 : SPINBAR는 ScrollBar 상속으로 처리, STEPBAR도 Step 상속으로 처리
    };

    // [component.scroll:created]                   // override 없음
    _pComplexComponent._createdScroll = function (win)
    {
        // _resetScroll로 모두 처리
    };

