    // [component.scroll.event.select:autoselect]     // Basic Component에서만 제한적 override
    _pComplexComponent._selectAutoScrollSelect = function (hpos, vpos)
    {
        if (this._onCheckSelectLeaderSync())
        {
            var celm = this.getElement();
            if (celm)
            {
                var wpos = celm._getPositionInWindow();
                var sb = this._getCurrentStyleBorder();

                var selm = nexacro.__getElementFromPoint(this._getWindow(), 
                                                        wpos[0]+sb._getBorderWidth(), 
                                                        wpos[1]+sb._getBorderHeight());
                if (selm)
                {
                    var item = selm.linkedcontrol;
                    if (item && item._itemindex !== undefined)
                        this._setSelectItem(item._itemindex);
                }
            }
        }
    };

