    // [component.scroll.scrolltype:apply]          // Basic Component에서만 제한적 override
    _pComplexComponent.on_apply_scrollbarprop = function ()
    {
        if (!this._is_created)
            return;

        // Scroll은 Scrollbar, Spin은 SpinBar, Popup은 ExpandBar로 처리
        switch (this._getOverflowType())
        {
            case 0x0008: // nexacro._PanelConst.SLOT_OVERFLOWTYPE_POPUP
                {
                    // expand bar   : _onResetExpandBar에서 추가처리
                    break;
                }
            case 0x0002: // nexacro._PanelConst.SLOT_OVERFLOWTYPE_SPIN
                {
                    var hspintype = this._getHSpinBarType();
                    var vspintype = this._getVSpinBarType();

                    if (hspintype == vspintype)
                    {
                        switch (vspintype)
                        {
                            case "auto":
                                {
                                    this._setLayoutAllowNC(true);
                                    this._setLayoutUnFixNC(true);
                                    break;
                                }
                            case "none":
                                {
                                    this._setLayoutAllowNC(false);
                                    this._setLayoutUnFixNC(false);
                                    break;
                                }
                            default: // case "fixed": case "indicator": case "autoindicator": 
                                {
                                    this._setLayoutAllowNC(true);
                                    this._setLayoutUnFixNC(false);
                                    break;
                                }
                        }
                    }
                    else
                    {
                        if (hspintype == "auto" || vspintype == "auto")
                        {
                            this._setLayoutAllowNC(true);
                            this._setLayoutUnFixNC(true);
                        }
                        else
                        {
                            this._setLayoutAllowNC(true);
                            this._setLayoutUnFixNC(false);
                        }
                    }

                    // spin bar     : _onResetScrollBar에서 추가처리
                    return nexacro.SimpleComponent.prototype.on_apply_spinbartype.call(this);
                }
            case 0x0004: // nexacro._PanelConst.SLOT_OVERFLOWTYPE_PAGING
            case 0x0001: // nexacro._PanelConst.SLOT_OVERFLOWTYPE_SCROLL
            default:
                {
                    var hscrollbartype = this._getHScrollBarType();
                    var vscrollbartype = this._getVScrollBarType();

                    if (hscrollbartype == vscrollbartype)
                    {
                        switch (vscrollbartype)
                        {
                            case "auto":
                                {
                                    this._setLayoutAllowNC(true);
                                    this._setLayoutUnFixNC(true);
                                    break;
                                }
                            case "none":
                                {
                                    this._setLayoutAllowNC(false);
                                    this._setLayoutUnFixNC(false);
                                    break;
                                }
                            default: // case "fixed": case "indicator": case "autoindicator": 
                                {
                                    this._setLayoutAllowNC(true);
                                    this._setLayoutUnFixNC(false);
                                    break;
                                }
                        }
                    }
                    else
                    {
                        if (hscrollbartype == "auto" || vscrollbartype == "auto")
                        {
                            this._setLayoutAllowNC(true);
                            this._setLayoutUnFixNC(true);
                        }
                        else
                        {
                            this._setLayoutAllowNC(true);
                            this._setLayoutUnFixNC(false);
                        }
                    }

                    // scroll bar     : _onResetScrollBar에서 추가처리
                    return nexacro.SimpleComponent.prototype.on_apply_scrollbartype.call(this);
                }
        }
    }

