    //===============================================================
    // nexacro.ComplexComponent : Expand
    //===============================================================

    // [ComplexComponent Component 처리]
    // Expand의 기본적인 구성은 ComplexComponent 에서 제공
    // Expand의 노출 i/f (prop/method/event)는 다양한 명칭과 방식이 요구됨으로
    // 각 하위 컴포넌트에서 각각 다른 명칭 / 형식으로 rename,override 하여 제공

    // TODO : Scroll/Expand 동시동작 처리
    //        NC Layout 포함 처리
    //        ComBase 통합

    // [component.expand:init]                      // 필요시 interface 추가
    _pComplexComponent._p_expandtype        = undefined;

    /*
    _pComplexComponent._p_expanddirtype     = undefined;    // expand control pos  : "auto" "horz" "vert"  | "afterheader" "beforefooter" ...
    _pComplexComponent._p_expandbartype     = undefined;    // expand control set  : "none" "button" "etc" | "auto" "fixed"...
    _pComplexComponent._p_expandbarsize     = undefined;    // expand control size : [width, height]
    _pComplexComponent._p_expandtrgtype     = undefined;    // expand trigger type : "click" "hover" ...
    */

    _pComplexComponent.expandbar = null;

    /*
    _pComplexComponent._default_expandtype    = "none";
    _pComplexComponent._default_expandbartype = "auto";
    _pComplexComponent._default_expandbarsize = [17, 17];
    _pComplexComponent._default_expandtrgtype = "click";
    */

    _pComplexComponent.set_expandtype         = function (v) { if (v != this._p_expandtype)    { this._p_expandtype    = v; this.on_apply_expandbarprop(); } };
    /*
    _pComplexComponent.set_expanddirtype      = function (v) { if (v != this._p_expanddirtype) { this._p_expanddirtype = v; this.on_apply_expandbarprop(); } };
    _pComplexComponent.set_expandbartype      = function (v) { if (v != this._p_expandbartype) { this._p_expandbartype = v; this.on_apply_expandbarprop(); } };
    _pComplexComponent.set_expandbarsize      = function (v) { if (v != this._p_expandbarsize) { this._p_expandbarsize = v; this.on_apply_expandbarprop(); } };
    _pComplexComponent.set_expandtriggertype  = function (v) { if (v != this._p_expandtrgtype) { this._p_expandtrgtype = v; this.on_apply_expandbarprop(); } };
    */

    _pComplexComponent.on_apply_expandbarprop = function ()
    {
        if (!this._is_created)
            return;

        this._resetExpand();
    };

    // [component.expand:create]                    // override 없음
    _pComplexComponent._createExpand = function ()
    {
        if (this._is_nc_expand)
        {
            // create manager
            this._createExpandManager();

            // create control --> Expand Control 실제 생성은 _resetExpand에서 일괄 동적 처리
            //  this._createExpandControl(); 
        }
    };
    // [component.expand.manager:create]            // override 없음
    _pComplexComponent._createExpandManager = function ()
    {
        if (this._use_expandmanager)
        {
            this._expandmanager = new nexacro._ExpandManager();

            // TODO: scrolltype/layout 재처리
            this._expandmanager._setExpandLayout(this._onGetExpandDirType(), this._onGetExpandActType(), this._onGetExpandCtrlSet(), this._onGetExpandVisible(), this._onGetExpandArrange(), this._onGetExpandCtrlOpt());
            this._expandmanager._setExpandEvent(this);
        }
    };
    // [component.expand.control:create]            // override 없음
    _pComplexComponent._createExpandControl = function ()
    {
        // _resetExpand로 모두 처리
        // this._createExpandBar();
    };

    // [component.expand.control:create]            // override 없음
    _pComplexComponent._createExpandBar = function (expanddirtype, expandacttype, expandctrlset, expandbarsize, expandarrange, expandctrlopt)
    {
        var ctrlsettype;
        var ctrlacttype;

        // get info
        if (this._use_expandmanager && this._expandmanager)
        {
            ctrlsettype = this._expandmanager.ctrlsettype;
        //  ctrloptions = this._expandmanager.ctrloptions;
            ctrlacttype = this._expandmanager.expandmode;
        }
        else
        {
            // TODO : Check Multi Enum
            ctrlsettype = nexacro._ExpandConst.EXPANDCTRLSET_CONVERT[expandctrlset];
        //  ctrloptions = nexacro._ExpandConst.EXPANDCTRLOPT_CONVERT[expandctrlopt];
            ctrlacttype = nexacro._ExpandConst.EXPANDACTTYPE_CONVERT[expandacttype];
        }

        /*
        if (nexacro._isNull(ctrlsettype)) ctrlsettype = nexacro._ExpandConst.EXPANDCTRLSET_CONVERT[this._default_expandctrlset];
        if (nexacro._isNull(ctrlacttype)) ctrlacttype = nexacro._ExpandConst.EXPANDACTTYPE_CONVERT[this._default_expandacttype];
        */

        // control create option --> 방향별 size fit은 ComBase에서 처리
        /*
        if (ctrloptions) // ctrloptions == nexacro._ExpandConst.EXPANDCTRLOPT_FIT
        {
            if (!expanddirtype)
                expanddirtype = this._isRowFirst() ? nexacro._ExpandConst.EXPANDDIRTYPE_HORZ : nexacro._ExpandConst.EXPANDDIRTYPE_VERT;

            if (expanddirtype == nexacro._ExpandConst.EXPANDDIRTYPE_HORZ)
                expandbarsize[0] = this._getClientWidth();
            else
                expandbarsize[1] = this._getClientHeight();
        }
        */

        // control create (recreate)
        switch (ctrlsettype)
        {
            default:
            case nexacro._ExpandConst.EXPANDCTRLSET_BUTTON:
                {
                    if (this.expandbar && this.expandbar._type_name && !this.expandbar._type_name.startsWith("Button"))
                    {
                        this._destroyExpandBar();
                    }
                    if (this.expandbar == null)
                    {
                        this.expandbar = this.createNCChildControl(new nexacro.Button("expandbar", 0, 0, expandbarsize[0], expandbarsize[1], null, null, null, null, null, null, this));
                    }
                    break;
                }
            case nexacro._ExpandConst.EXPANDCTRLSET_CHECK:
                {
                    if (this.expandbar && this.expandbar._type_name && !this.expandbar._type_name.startsWith("CheckBox"))
                    {
                        this._destroyExpandBar();
                    }
                    if (this.expandbar == null)
                    {
                        this.expandbar = this.createNCChildControl(new nexacro.CheckBox("expandbar", 0, 0, expandbarsize[0], expandbarsize[1], null, null, null, null, null, null, this));
                    }
                    break;
                }
            case nexacro._ExpandConst.EXPANDCTRLSET_CUSTOM:
                {
                    if (this.expandbar == null)
                    {
                        var control = this._createExpandBarCustom("expandbar", 0, 0, expandbarsize[0], expandbarsize[1]);
                        if (control._is_subcontrol)
                        {
                            this.expandbar = this.createNCChild(control);
                        }
                        else
                        {
                            this.expandbar = this.createNCChildControl(control);
                        }
                        break;
                    }
                }
        }

        switch (ctrlacttype)
        {
            case nexacro._ExpandConst.EXPANDACTTYPE_ACTION:
            case nexacro._ExpandConst.EXPANDACTTYPE_CLICK:
                {
                    if (this.expandbar)
                        this.expandbar._setEventHandler("onclick", this.on_notify_expand_onclick, this);
                    break;
                }
            /*
            case nexacro._ExpandConst.EXPANDACTTYPE_HOVER:
            case nexacro._ExpandConst.EXPANDACTTYPE_NONE:
            default:
                {
                    break;
                }
            */
        }
    };
    _pComplexComponent._createExpandBarCustom = function ()
    {
    };

