    // [component.taborder:get]                      // Accessibility 용 별도 처리시 override
    _pComplexComponent._getTabOrderFirst = function (filter, bAcc)
    {
        // [component.accessibility.taborder:first]
        if (this._is_items && this.__focus_taborder)
        {
            var firstitemidx = +(this._useheadfocus ? 0 : (this._getItemHeadCount() ? 1 : 0)) + 0;
            return this._getItemSingle(firstitemidx);
        }
    };
    _pComplexComponent._getTabOrderLast = function (filter, bAcc)
    {
        // [component.accessibility.taborder:last]
        if (this._is_items && this.__focus_taborder)
        {
            var finalitemidx = -(this._usetailfocus ? 1 : (this._getItemTailCount() ? 2 : 1)) + this._getItemCount(true, true);
            return this._getItemSingle(finalitemidx);
        }
    };

