    //===============================================================
    // nexacro.ComplexComponent : Status
    //===============================================================

    // [Simple Component 처리]
    // 상태는 기본적으로 Basic Component에서 모두 제공하도록 구성
    // User Component에서는 추가된 UserStatus를 사용만 코딩하며 Metainfo에만 노출
    // 명시적인 상태를 추가하려면 Property/Method Interface를 이용하여 처리한다.

    // [ComplexComponent Component 처리]
    // 상태관련 Override는 Basic Component에서만 허용
    // 상태의 처리는 _changeUserStatus 메소드 호출로 처리

    _pComplexComponent._onInitStatus = function ()
    {
        // status init logic             
    };

    _pComplexComponent._spreadStatus = function (statusname, statusstat)
    {
        if (this._is_child) this._onSpreadStatusChild(statusname, statusstat);
        if (this._is_items) this._onSpreadStatusItems(statusname, statusstat);

        if (this._is_nc_expand) this._onSpreadStatusExpand(statusname, statusstat);
        if (this._is_nc_scroll) this._onSpreadStatusScroll(statusname, statusstat);
        if (this._is_nc_layout) this._onSpreadStatusNCCtrl(statusname, statusstat);
    };

    _pComplexComponent._onSpreadStatusChild = function (statusname, statusstat)
    {
        var complist = this._getChildren(); if (!complist) return;

        switch (statusname)
        {
            case "disabled":
                {
                    if (statusstat) for (var comp of complist) if (comp) comp._changeStatus(comp, statusname, statusstat);
                    else            for (var comp of complist) if (comp) comp._changeStatus(comp, statusname, comp._p_enable);

                    break;
                }
            case "readonly":
                {
                    if (statusstat) for (var comp of complist) if (comp) comp._changeStatus(comp, statusname, statusstat);
                    else            for (var comp of complist) if (comp) comp._changeStatus(comp, statusname, comp._p_readonly);

                    break;
                }
        }
    };

    _pComplexComponent._onSpreadStatusItems = function (statusname, statusstat)
    {
        var complist = this._getItems(); if (!complist) return;

        switch (statusname)
        {
            case "disabled":
                {
                    if (statusstat) for (var comp of complist) if (comp) { comp._changeStatus(comp, statusname, statusstat);        comp._spreadStatus(statusname, statusstat); }
                    else            for (var comp of complist) if (comp) { comp._changeStatus(comp, statusname, comp._p_enable);    comp._spreadStatus(statusname, statusstat); }

                    break;
                }
            case "readonly":
                {
                    if (statusstat) for (var comp of complist) if (comp) { comp._changeStatus(comp, statusname, statusstat);        comp._spreadStatus(statusname, statusstat); }
                    else            for (var comp of complist) if (comp) { comp._changeStatus(comp, statusname, comp._p_readonly);  comp._spreadStatus(statusname, statusstat); }

                    break;
                }
        }
    };

    _pComplexComponent._onSpreadStatusExpand = function (statusname, statusstat)
    {
        if (this.expandbar)
        {
            if (statusname == "disabled")
            {
                this.expandbar._setEnable(statusstat);
            }
        }
    };

    _pComplexComponent._onSpreadStatusScroll = function (statusname, statusstat)
    {
        if (this._is_scrollable)
        {
            if (statusname == "disabled")
            {
                if (this._p_vscrollbar) this._p_vscrollbar._setEnable(statusstat);
                if (this._p_hscrollbar) this._p_hscrollbar._setEnable(statusstat);
                if (this._p_vspinbar)   this._p_vspinbar._setEnable(statusstat);
                if (this._p_hspinbar)   this._p_hspinbar._setEnable(statusstat);
            }
        }
    };
    
    _pComplexComponent._onSpreadStatusNCCtrl = function (statusname, statusstat)
    {
        if (this._is_nc_layout)
        {
            if (statusname == "disabled")
            {
                var ctrllist = this._getNCChildren(); if (!ctrllist) return;

                for (var ctrl of ctrllist) if (ctrl) { ctrl._setEnable(statusstat); }
            }
        }        
    }; 

    _pComplexComponent._convertItemStatusCode2Name = function (statuscode)
    {
        switch (statuscode)
        {
            case  1: return "expand";
            case -1: return "collapse";
            case  2: return "popup";
            case -2: return "close";
            default: return "";
        }
    }

