    // Wheel Event
    _pComplexComponent._usehorzwheel = true;

    // [component.event.mousewheel:defaultaction]
    _pComplexComponent.on_mousewheel_default_action = function (wheelDeltaX, wheelDeltaY, shiftkey, usehorzwheel)
    {
        var horzwheel = usehorzwheel ?? this._usehorzwheel;
        var chgscroll = nexacro.SimpleComponent.prototype.on_mousewheel_default_action.call(this, wheelDeltaX, wheelDeltaY, shiftkey, horzwheel);
        if (chgscroll)
        {
            switch (this._getScrollType())
            {
                case "vertical":
                    if (shiftkey) break;
                    if (wheelDeltaY)                return this._setVScrollDefaultAction(wheelDeltaY, false);
                //  if (wheelDeltaX)                return this._setVScrollDefaultAction(wheelDeltaX, false);
                    break;
                case "horizontal":
                    if (!shiftkey && !horzwheel) break;
                    if (wheelDeltaX)                return this._setHScrollDefaultAction(wheelDeltaX, !shiftkey);
                    if (wheelDeltaY)                return this._setHScrollDefaultAction(wheelDeltaY, !shiftkey);
                    break;
                case "both":
                    if (wheelDeltaY && !shiftkey)   return this._setVScrollDefaultAction(wheelDeltaY, false);
                    if (wheelDeltaX &&  shiftkey)   return this._setHScrollDefaultAction(wheelDeltaX, false);
                    break;
                case "none":
                    break;
            }
        }

        return chgscroll;
    };
  
    // [component.event.mousewheel:defaultaction]
    _pComplexComponent._setVScrollDefaultAction = function (wheelDelta, actdefault)
    {
        var ret = true;

        if (actdefault)
        {
            ret = nexacro.SimpleComponent.prototype._setVScrollDefaultAction.call(this, wheelDelta);
        }
        if (ret)
        {
            this._updateItemVScrollInfo(this._vscroll_pos, "trackwheel", true);
            this._changeItemVScrollInfo(this._vscroll_pos, "trackwheel", false);
        }

        var cem = this._control_element;
        if (cem)
        {
            this._isscrolllast = wheelDelta < 0 ? this._vscroll_pos <= 0 : this._vscroll_pos >= cem.vscroll_limit;
        }

        return ret;
    };
    // [component.event.mousewheel:defaultaction]
    _pComplexComponent._setHScrollDefaultAction = function (wheelDelta, actdefault)
    {
        var ret = true;

        if (actdefault)
        {
            ret = nexacro.SimpleComponent.prototype._setHScrollDefaultAction.call(this, wheelDelta);
        }
        if (ret)
        {
            this._updateItemHScrollInfo(this._hscroll_pos, "trackwheel", true);
            this._changeItemHScrollInfo(this._hscroll_pos, "trackwheel", false);
        }

        var cem = this._control_element;
        if (cem)
        {
            this._isscrolllast = wheelDelta < 0 ? this._hscroll_pos <= 0 : this._hscroll_pos >= cem.hscroll_limit;
        }

        return ret;
    };


