    // [component.event.keydown:defaultaction]
    _pComplexComponent.on_keydown_default_action = function (key_code, alt_key, ctrl_key, shift_key, refer_comp, meta_key)
    {
        // 하위에서 처리완료시 상위에서 처리하지 않도록 초기화
        this._setProcessedKeyDone(refer_comp, false);

        return nexacro.SimpleComponent.prototype.on_keydown_default_action.call(this, key_code, alt_key, ctrl_key, shift_key, refer_comp, meta_key);
    };
    /*
    // [component.event.keydown:fireuserevent]
    _pComplexComponent.on_fire_user_onkeydown = function (key_code, alt_key, ctrl_key, shift_key, from_comp, from_refer_comp, meta_key)
    {
        return nexacro.SimpleComponent.prototype.on_fire_user_onkeydown.call(this, key_code, alt_key, ctrl_key, shift_key, from_comp, from_refer_comp, meta_key);
    };
    */
    // [component.event.keydown:firesysevent]
    _pComplexComponent.on_fire_sys_onkeydown = function (key_code, alt_key, ctrl_key, shift_key, from_comp, from_refer_comp, meta_key)
    {
        var ret = nexacro.SimpleComponent.prototype.on_fire_sys_onkeydown.call(this, key_code, alt_key, ctrl_key, shift_key, from_comp, from_refer_comp, meta_key);
        if (ret) return ret;

        // 하위에서 처리완료시 상위에서 처리하지 않도록 체크처리
        var done = this._getProcessedKeyDone(from_refer_comp);
        if (done) return done;

        // action keydown // TODO : action 형식으로 처리
        switch (this._checkActionKeyInfo(key_code, alt_key, ctrl_key, shift_key, from_comp, from_refer_comp, meta_key))
        {
            case "select": done = this._selectItemKeyInfo(key_code, alt_key, ctrl_key, shift_key); break;
            case "scroll": done = this._scrollItemKeyInfo(key_code, alt_key, ctrl_key, shift_key); break;
            case "expand": done = this._expandItemKeyInfo(key_code, alt_key, ctrl_key, shift_key); break;
            case "custom": done = this._customItemKeyInfo(key_code, alt_key, ctrl_key, shift_key); break;
        }

        this._setProcessedKeyDone(from_refer_comp, done);

        return done;
    };
